import os
import sys
import math
import traceback
import types
import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

# ModelNew: drop-in replacement for Model, accelerating batched matmul via a CUDA extension.
# Strategy:
# - Use a custom tiled CUDA kernel for small/moderate sizes during inference (no autograd).
# - For training or large sizes, dispatch to cuBLAS via at::bmm inside the same extension to preserve autograd and peak performance.
# - Fall back to torch.bmm if compilation fails or inputs are unsupported.

def _build_bmm_extension():
    cpp_src = r"""
    #include <torch/extension.h>

    // Exposed function declaration
    torch::Tensor bmm_forward(torch::Tensor A, torch::Tensor B);
    """

    cuda_src = r"""
    #include <torch/extension.h>
    #include <ATen/cuda/CUDAContext.h>
    #include <cuda_runtime.h>

    template<int TILE>
    __global__ void bmm_kernel_tiled(const float* __restrict__ A,
                                     const float* __restrict__ B,
                                     float* __restrict__ C,
                                     int BATCH, int M, int N, int K) {
      // Grid: (ceil_div(N,TILE), ceil_div(M,TILE), BATCH)
      // Block: (TILE, TILE)
      int b = blockIdx.z;
      int row = blockIdx.y * TILE + threadIdx.y;
      int col = blockIdx.x * TILE + threadIdx.x;

      extern __shared__ float smem[];
      float* As = smem;                        // TILE*TILE
      float* Bs = smem + TILE * TILE;          // TILE*TILE

      float acc = 0.0f;

      int num_tiles = (K + TILE - 1) / TILE;
      const float* A_b = A + (int64_t)b * M * K;
      const float* B_b = B + (int64_t)b * K * N;

      for (int t = 0; t < num_tiles; ++t) {
        int kA = t * TILE + threadIdx.x; // column in A
        float a_val = 0.0f;
        if (row < M && kA < K) {
          a_val = A_b[(int64_t)row * K + kA];
        }
        As[threadIdx.y * TILE + threadIdx.x] = a_val;

        int kB = t * TILE + threadIdx.y; // row in B
        float b_val = 0.0f;
        if (kB < K && col < N) {
          b_val = B_b[(int64_t)kB * N + col];
        }
        Bs[threadIdx.y * TILE + threadIdx.x] = b_val;

        __syncthreads();

        #pragma unroll
        for (int kk = 0; kk < TILE; ++kk) {
          float a_elem = As[threadIdx.y * TILE + kk];
          float b_elem = Bs[kk * TILE + threadIdx.x];
          acc += a_elem * b_elem;
        }
        __syncthreads();
      }

      if (row < M && col < N) {
        C[(int64_t)b * M * N + (int64_t)row * N + col] = acc;
      }
    }

    torch::Tensor bmm_forward(torch::Tensor A, torch::Tensor B) {
      TORCH_CHECK(A.is_cuda(), "A must be a CUDA tensor");
      TORCH_CHECK(B.is_cuda(), "B must be a CUDA tensor");
      TORCH_CHECK(A.dim() == 3 && B.dim() == 3, "A and B must be 3D tensors [B, M, K] and [B, K, N]");
      TORCH_CHECK(A.size(0) == B.size(0), "Batch dimensions must match");
      TORCH_CHECK(A.size(2) == B.size(1), "Inner dimensions must match: A[..., K] vs B[K, ...]");

      auto batch = (int)A.size(0);
      auto M = (int)A.size(1);
      auto K = (int)A.size(2);
      auto N = (int)B.size(2);

      // Only float32 kernel supported. For other dtypes, dispatch to at::bmm.
      bool supported_dtype = (A.scalar_type() == at::kFloat && B.scalar_type() == at::kFloat);

      // Make contiguous copies
      auto A_c = A.contiguous();
      auto B_c = B.contiguous();

      // If gradients are required or dtype unsupported, dispatch to cuBLAS-backed at::bmm for correctness and speed.
      if (!supported_dtype || A.requires_grad() || B.requires_grad()) {
        return at::bmm(A_c, B_c);
      }

      // Heuristic: use custom kernel for moderately sized problems to reduce overhead.
      // For large problems, at::bmm (cuBLAS) is typically faster.
      bool use_kernel = (M <= 512 && N <= 512 && K <= 512);
      if (!use_kernel) {
        return at::bmm(A_c, B_c);
      }

      auto options = A_c.options();
      auto C = at::empty({A_c.size(0), A_c.size(1), B_c.size(2)}, options);

      const float* Ap = A_c.data_ptr<float>();
      const float* Bp = B_c.data_ptr<float>();
      float* Cp = C.data_ptr<float>();

      cudaStream_t stream = at::cuda::getCurrentCUDAStream();

      // Choose TILE size based on problem size
      int TILE = (M >= 128 && N >= 128) ? 32 : 16;
      dim3 block((unsigned)TILE, (unsigned)TILE, 1);
      dim3 grid((unsigned)((N + TILE - 1) / TILE),
                (unsigned)((M + TILE - 1) / TILE),
                (unsigned)batch);
      size_t shmem = (size_t)(2 * TILE * TILE) * sizeof(float);

      if (TILE == 32) {
        bmm_kernel_tiled<32><<<grid, block, shmem, stream>>>(Ap, Bp, Cp, batch, M, N, K);
      } else {
        bmm_kernel_tiled<16><<<grid, block, shmem, stream>>>(Ap, Bp, Cp, batch, M, N, K);
      }
      C10_CUDA_KERNEL_LAUNCH_CHECK();
      return C;
    }
    """

    # Build with a semi-unique name to avoid clashes across processes
    unique_name = f"bmm_ext_{os.getpid()}_{torch.randint(0, 2**31-1, ()).item()}"
    ext = load_inline(
        name=unique_name,
        cpp_sources=[cpp_src],
        cuda_sources=[cuda_src],
        functions=["bmm_forward"],
        extra_cflags=["-O3"],
        extra_cuda_cflags=["-O3", "-use_fast_math"],
        verbose=True,
    )
    return ext


class ModelNew(nn.Module):
    """
    Drop-in replacement for Model.
    Performs batched matrix multiplication (C = A * B) with a CUDA extension fast path.
    """
    _ext = None
    _ext_ok = None

    def __init__(self):
        super(ModelNew, self).__init__()
        # Build the extension once per process
        if ModelNew._ext_ok is None:
            try:
                if torch.cuda.is_available():
                    ModelNew._ext = _build_bmm_extension()
                    ModelNew._ext_ok = True
                else:
                    ModelNew._ext = None
                    ModelNew._ext_ok = False
            except Exception as e:
                # Log and fall back to PyTorch path
                traceback.print_exc()
                ModelNew._ext = None
                ModelNew._ext_ok = False
        self.use_ext = bool(ModelNew._ext_ok)

    def forward(self, A: torch.Tensor, B: torch.Tensor) -> torch.Tensor:
        """
        Performs batched matrix multiplication.

        Args:
            A: Input tensor of shape (batch_size, m, k).
            B: Input tensor of shape (batch_size, k, n).

        Returns:
            C: Output tensor of shape (batch_size, m, n).
        """
        # Validation mirrors the original semantics
        if not isinstance(A, torch.Tensor) or not isinstance(B, torch.Tensor):
            raise TypeError("A and B must be torch.Tensors")
        if A.dim() != 3 or B.dim() != 3:
            raise ValueError("A and B must be 3D tensors of shapes [B, M, K] and [B, K, N]")
        if A.size(0) != B.size(0) or A.size(2) != B.size(1):
            raise ValueError("Batch dims must match and inner dims must align: A[...,K] vs B[K,...]")

        # Extension fast path: CUDA, supported dtype, and extension available.
        if self.use_ext and A.is_cuda and B.is_cuda:
            try:
                # The extension wrapper will select either the custom kernel (inference, small sizes)
                # or cuBLAS-backed at::bmm (training or large sizes).
                return ModelNew._ext.bmm_forward(A, B)
            except Exception:
                # Fallback to PyTorch if anything goes wrong
                pass

        # Fallback path
        return torch.bmm(A, B)


# Optional helpers mirroring the reference (not required for API compatibility)
batch_size = 128
m = 128 * 4
k = 256 * 4
n = 512 * 4

def get_inputs():
    A = torch.rand(batch_size, m, k)
    B = torch.rand(batch_size, k, n)
    return [A, B]

def get_init_inputs():
    return []  # No special initialization inputs needed

prompts.kernel_gen_prompt:
You are given a PyTorch model definition (Model). Produce a single Python file that defines ModelNew as a drop-in replacement for Model and accelerates the forward pass by using one or more custom CUDA kernels built with torch.utils.cpp_extension.load_inline.

Primary objective
- Achieve meaningful speedup over the PyTorch baseline while preserving numerical correctness and API compatibility.
- Prioritize ops that are memory-bound or elementwise-heavy where fusion yields clear wins (e.g., LayerNorm, Softmax, BatchNorm2d forward, MaxPool2d, fused bias+activation). For GEMM-heavy paths, keep matmul in PyTorch (cuBLAS-backed) and only fuse cheap elementwise parts.

Hard requirements (must pass)
- Keep the exact same __init__ signature and forward signature as Model. Same inputs -> same outputs and shapes.
- Numerical parity with the PyTorch reference (match PyTorch semantics; small FP32 diffs acceptable).
- Use torch.utils.cpp_extension.load_inline to JIT-compile CUDA code at import or module init time.
- The extension must compile cleanly on CUDA 11+/12+ without extra system dependencies.
- Do not define PYBIND11_MODULE anywhere (load_inline with functions= handles binding).
- Use correct headers and stream handling; avoid APIs that commonly fail across Torch builds.

Extension structure and safety rules
- Build the extension exactly once (e.g., during ModelNew.__init__). Cache the handle and set a flag to fall back to PyTorch ops if compilation fails.
- Separate sources:
  - cpp_sources: only function declarations (no implementations, no PYBIND11_MODULE).
  - cuda_sources: includes, kernel(s), and C++ wrapper implementations that call kernels.
  - functions: list of function names to expose (must match declarations exactly).
- Includes:
  - In both C++ and CUDA sources: #include <torch/extension.h>
  - In CUDA sources also include: #include <ATen/cuda/CUDAContext.h> and #include <cuda_runtime.h>
  - Do NOT include cuda.h. Do NOT use at::cuda::CUDAGuard. If you need a guard, use c10::cuda::CUDAGuard from <c10/cuda/CUDAGuard.h>; otherwise rely on the current device from tensor arguments and launch on the current stream.
- Stream: get the current stream via at::cuda::getCurrentCUDAStream() and pass it to kernel launches.
- Types: Implement float32 first unless the model uses another dtype. You may cast inputs to float32 for the accelerated op and cast back if necessary to preserve speed/correctness.

Strategy for choosing what to accelerate
- Replace hotspot operators that are memory-bound or benefit from fusion:
  - LayerNorm over trailing dims
  - Softmax (stable: subtract max; optionally fuse mask/bias)
  - BatchNorm2d forward (train/infer; update running stats during training)
  - MaxPool2d
  - Fused bias + activation sequences (e.g., GELU/ReLU after linear)
- For attention blocks:
  - Keep QK^T and value matmuls in PyTorch via at::matmul/at::bmm.
  - Implement a custom softmax (with optional masking, scaling) and/or fuse subsequent elementwise ops.
- For RNN/LSTM:
  - Use at::matmul/at::bmm for GEMMs. Optionally fuse gate activations and elementwise cell updates in a custom kernel. Do NOT implement GEMM yourself.

LayerNorm: preferred optimized plan (fast and robust)
- Normalize along the trailing normalized_shape dimensions. Flatten input to [B, M] where:
  - M = product(normalized_shape), B = input.numel() // M
- Implement a single-kernel, two-phase per-row algorithm:
  - Phase 1 (in-kernel): compute per-row mean and variance using Welford’s online algorithm for numerical stability, with warp- and block-level reductions.
  - Phase 2 (in-kernel): re-iterate over the same row to write normalized output and apply affine y = (x - mean) * inv_std * weight + bias.
  - This keeps kernel launch overhead low and avoids extra global buffers for statistics.
- Kernel details:
  - Grid: one block per row (B blocks). For typical M (e.g., 256–8192), this is efficient. For very large M, use a grid-stride loop inside the block.
  - Threads: 256 or 512 threads per block. Use grid-stride loops to cover M.
  - Reductions: use warp shuffle intrinsics (__shfl_down_sync) to reduce within warps, then shared memory to reduce across warps.
  - Vectorization: for large M and aligned pointers, use float2/float4 loads and stores to increase bandwidth. Fallback to scalar tail handling.
  - Weight/bias: per-element vectors of length M (flattened normalized_shape). Treat weight/bias as optional; if None, skip affine.
  - eps handling: inv_std = 1.0f / sqrtf(var + eps) to match PyTorch semantics.
- Exposed binding signature (example):
  - torch::Tensor layernorm_forward(torch::Tensor input_2d, torch::Tensor weight_1d, torch::Tensor bias_1d, double eps);
