import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

# Build the CUDA-backed extension at import-time (cached by PyTorch).
# Robustness: only build when CUDA is available; otherwise fall back to PyTorch ops.
_kb_ext = None
try:
