    #include <torch/extension.h>
    #include <ATen/cuda/CUDAContext.h>
    #include <cuda_runtime.h>

    constexpr int TILE_M = 32;
    constexpr int TILE_N = 32;
    constexpr int TILE_K = 32;

    __global__ void tiled_gemm_kernel(const float* __restrict__ A,
                                      const float* __restrict__ B,
                                      float* __restrict__ C,
                                      int M, int N, int K) {
        __shared__ float As[TILE_M][TILE_K];
        __shared__ float Bs[TILE_K][TILE_N];

        int row = blockIdx.y * TILE_M + threadIdx.y;
        int col = blockIdx.x * TILE_N + threadIdx.x;

        float acc = 0.f;
        int tiles = (K + TILE_K - 1) / TILE_K;

        for (int t = 0; t < tiles; ++t) {
            int a_col = t * TILE_K + threadIdx.x;
            int b_row = t * TILE_K + threadIdx.y;

            As[threadIdx.y][threadIdx.x] = (row < M && a_col < K) ? A[row * K + a_col] : 0.f;
            Bs[threadIdx.y][threadIdx.x] = (b_row < K && col < N) ? B[b_row * N + col] : 0.f;
            __syncthreads();

            #pragma unroll
            for (int k = 0; k < TILE_K; ++k) {
                acc += As[threadIdx.y][k] * Bs[k][threadIdx.x];
            }
            __syncthreads();
        }

        if (row < M && col < N) {
            C[row * N + col] = acc;
        }
    }

    torch::Tensor matmul_cuda(torch::Tensor A, torch::Tensor B) {
        TORCH_CHECK(A.is_cuda() && B.is_cuda(), "Inputs must be CUDA tensors");
        TORCH_CHECK(A.dim() == 2 && B.dim() == 2, "Inputs must be 2D matrices");
        TORCH_CHECK(A.scalar_type() == torch::kFloat && B.scalar_type() == torch::kFloat, "Use float32 for now");
        TORCH_CHECK(A.size(1) == B.size(0), "Incompatible shapes for matmul: A [M,K], B [K,N]");

        A = A.contiguous();
        B = B.contiguous();

        const int M = A.size(0);
        const int K = A.size(1);
        const int N = B.size(1);

        auto C = torch::empty({M, N}, A.options());

        dim3 block(TILE_N, TILE_M);
        dim3 grid((N + TILE_N - 1) / TILE_N, (M + TILE_M - 1) / TILE_M);

        cudaStream_t stream = at::cuda::getCurrentCUDAStream();
        tiled_gemm_kernel<<<grid, block, 0, stream>>>(
            A.data_ptr<float>(), B.data_ptr<float>(), C.data_ptr<float>(), M, N, K);

        return C;
    }
