# Copyright (c) 2026
# Self-contained Python file building a CUDA extension and defining ModelNew
# that accelerates C = A^T @ B^T by leveraging cuBLAS via ATen in a CUDA-compiled
# host function. This avoids Python-level overhead and keeps execution on the
# current PyTorch CUDA stream.

import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

# Declarations must include torch/extension.h when using functions=...
_cpp_decls = r"""
#include <torch/extension.h>
torch::Tensor matmul_at_bt_aten(torch::Tensor A, torch::Tensor B);
"""

# Implement the host function in a CUDA translation unit; no device kernel is needed
# because we delegate to ATen/cuBLAS. Keep it minimal and robust.
_cuda_impl = r"""
#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>
#include <cuda_runtime.h>

torch::Tensor matmul_at_bt_aten(torch::Tensor A, torch::Tensor B) {
    TORCH_CHECK(A.dim() == 2 && B.dim() == 2, "A and B must be 2D tensors");
    TORCH_CHECK(A.device().is_cuda() && B.device().is_cuda(), "Inputs must be CUDA tensors");
    TORCH_CHECK(A.scalar_type() == at::kFloat && B.scalar_type() == at::kFloat, "Only float32 is supported");

    // Expected shapes from the reference harness:
    // A: (K, M), B: (N, K)
    const int64_t K = A.size(0);
    const int64_t M = A.size(1);
    TORCH_CHECK(B.size(1) == K, "B.size(1) must equal A.size(0)");
    const int64_t N = B.size(0);

    // Use transpose views to express A^T @ B^T, letting ATen route to cuBLAS with proper transpose flags.
    // This keeps data on the current CUDA stream managed by PyTorch.
    auto At = A.transpose(0, 1); // (M, K)
    auto Bt = B.transpose(0, 1); // (K, N)

    auto C = at::matmul(At, Bt); // (M, N)
    TORCH_CHECK(C.size(0) == M && C.size(1) == N, "Output shape mismatch");
    return C;
}
"""

kb_ext = None
try:
    if torch.cuda.is_available():
        kb_ext = load_inline(
            name="kb_ext",
            cpp_sources=[_cpp_decls],
            cuda_sources=[_cuda_impl],
            functions=["matmul_at_bt_aten"],
            with_cuda=True,
            extra_cflags=["-O3"],
            extra_cuda_cflags=["-O3"],
            verbose=False,
        )
except Exception:
    kb_ext = None


class ModelNew(nn.Module):
