    """
    def __init__(self):
        super(ModelNew, self).__init__()

    def forward(self, A: torch.Tensor, B: torch.Tensor) -> torch.Tensor:
        """
        Performs matrix multiplication: C = A^T @ B^T

        Args:
            A: Input tensor of shape (K, M).
            B: Input tensor of shape (N, K).

        Returns:
            Output tensor of shape (M, N).
        """
        # Use extension only for float32 CUDA tensors; otherwise, fallback to PyTorch.
        if (
            kb_ext is not None
            and A.is_cuda and B.is_cuda
            and A.dtype == torch.float32 and B.dtype == torch.float32
        ):
            return kb_ext.matmul_at_bt_aten(A, B)
        else:
            # PyTorch reference path
            return torch.matmul(A.T, B.T)


