import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

_kb_layernorm_mod = None

def _get_kb_layernorm_mod():
    global _kb_layernorm_mod
    if _kb_layernorm_mod is not None:
        return _kb_layernorm_mod
    if not torch.cuda.is_available():
        return None
    try:
        _kb_layernorm_mod = load_inline(
            name="kb_layernorm_vec",
            cpp_sources=r"""
#include <torch/extension.h>
#include <vector>

// Forward declaration only (implementation in CUDA file)
torch::Tensor layernorm_forward(torch::Tensor input,
                                torch::Tensor weight,
                                torch::Tensor bias,
                                double eps,
                                std::vector<int64_t> normalized_shape);
""",
            cuda_sources=r"""
#include <torch/extension.h>
#include <cuda_runtime.h>
#include <ATen/cuda/CUDAContext.h>
#include <stdint.h>
#include <vector>

#ifndef KB_WARP_SIZE
#define KB_WARP_SIZE 32
#endif

__inline__ __device__ float warp_sum(float v) {
    unsigned mask = 0xffffffffu;
    #pragma unroll
    for (int offset = KB_WARP_SIZE / 2; offset > 0; offset >>= 1) {
        v += __shfl_down_sync(mask, v, offset);
    }
    return v;
}

// Kernel: compute per-row mean and inv_std for a [B, M] matrix
__global__ void rowwise_stats_kernel(const float* __restrict__ x,
                                     float* __restrict__ mean,
                                     float* __restrict__ inv_std,
                                     int64_t B,
                                     int64_t M,
                                     float eps) {
    int64_t row = blockIdx.x;
    if (row >= B) return;

    const float* row_ptr = x + row * M;

    bool use_vec4 = ((reinterpret_cast<uintptr_t>(row_ptr) & 0xF) == 0) && (M % 4 == 0);

    float thread_sum = 0.0f;
    float thread_sumsq = 0.0f;

    if (use_vec4) {
        const float4* row_v4 = reinterpret_cast<const float4*>(row_ptr);
        int64_t M4 = M >> 2;
        for (int64_t j = threadIdx.x; j < M4; j += blockDim.x) {
            float4 v = row_v4[j];
            thread_sum   += (v.x + v.y + v.z + v.w);
            thread_sumsq += (v.x * v.x + v.y * v.y + v.z * v.z + v.w * v.w);
        }
    } else {
        for (int64_t j = threadIdx.x; j < M; j += blockDim.x) {
            float v = row_ptr[j];
            thread_sum   += v;
            thread_sumsq += v * v;
        }
    }

    // Reduce within warp
    thread_sum = warp_sum(thread_sum);
    thread_sumsq = warp_sum(thread_sumsq);

    // Shared memory to collect per-warp results
    int warp_id = threadIdx.x / KB_WARP_SIZE;
    int lane = threadIdx.x % KB_WARP_SIZE;
    int warp_count = (blockDim.x + KB_WARP_SIZE - 1) / KB_WARP_SIZE;
    extern __shared__ float smem[];
    float* smem_sum = smem;
    float* smem_sumsq = smem + warp_count;

    if (lane == 0) {
        smem_sum[warp_id] = thread_sum;
        smem_sumsq[warp_id] = thread_sumsq;
    }
    __syncthreads();

    if (warp_id == 0) {
        float val_sum = (lane < warp_count) ? smem_sum[lane] : 0.0f;
        float val_sumsq = (lane < warp_count) ? smem_sumsq[lane] : 0.0f;
        val_sum = warp_sum(val_sum);
        val_sumsq = warp_sum(val_sumsq);
        if (lane == 0) {
            float mean_r = val_sum / static_cast<float>(M);
            float var_r = val_sumsq / static_cast<float>(M) - mean_r * mean_r;
            var_r = var_r < 0.0f ? 0.0f : var_r; // numerical guard
            float inv = rsqrtf(var_r + eps);
            mean[row] = mean_r;
            inv_std[row] = inv;
        }
    }
}

// Kernel: normalize and apply affine per row
__global__ void layernorm_affine_kernel(const float* __restrict__ x,
                                        const float* __restrict__ weight,
                                        const float* __restrict__ bias,
                                        const float* __restrict__ mean,
                                        const float* __restrict__ inv_std,
                                        float* __restrict__ y,
                                        int64_t B,
                                        int64_t M) {
    int64_t row = blockIdx.x;
    if (row >= B) return;

    const float* row_x = x + row * M;
    float* row_y = y + row * M;
    float m = mean[row];
    float inv = inv_std[row];

    bool use_vec4 = ((reinterpret_cast<uintptr_t>(row_x) & 0xF) == 0) &&
                    ((reinterpret_cast<uintptr_t>(weight) & 0xF) == 0) &&
                    ((reinterpret_cast<uintptr_t>(bias) & 0xF) == 0) &&
                    ((reinterpret_cast<uintptr_t>(row_y) & 0xF) == 0) &&
                    (M % 4 == 0);

    if (use_vec4) {
        const float4* x_v4 = reinterpret_cast<const float4*>(row_x);
        const float4* w_v4 = reinterpret_cast<const float4*>(weight);
        const float4* b_v4 = reinterpret_cast<const float4*>(bias);
        float4* y_v4 = reinterpret_cast<float4*>(row_y);
        int64_t M4 = M >> 2;
        for (int64_t j = threadIdx.x; j < M4; j += blockDim.x) {
            float4 xv = x_v4[j];
            float4 wv = w_v4[j];
            float4 bv = b_v4[j];
            float4 out;
            out.x = ((xv.x - m) * inv) * wv.x + bv.x;
            out.y = ((xv.y - m) * inv) * wv.y + bv.y;
            out.z = ((xv.z - m) * inv) * wv.z + bv.z;
            out.w = ((xv.w - m) * inv) * wv.w + bv.w;
            y_v4[j] = out;
        }
    } else {
        for (int64_t j = threadIdx.x; j < M; j += blockDim.x) {
            float xv = row_x[j];
            float out = ((xv - m) * inv) * weight[j] + bias[j];
            row_y[j] = out;
        }
    }
}

static inline int next_pow2_int(int v) {
    v--;
    v |= v >> 1;
    v |= v >> 2;
    v |= v >> 4;
    v |= v >> 8;
    v |= v >> 16;
    v++;
    return v;
}

// Host function exposed to Python
torch::Tensor layernorm_forward(torch::Tensor input,
                                torch::Tensor weight,
                                torch::Tensor bias,
                                double eps,
                                std::vector<int64_t> normalized_shape) {
    TORCH_CHECK(input.is_cuda(), "layernorm_forward: input must be CUDA");
    TORCH_CHECK(weight.is_cuda(), "layernorm_forward: weight must be CUDA");
    TORCH_CHECK(bias.is_cuda(), "layernorm_forward: bias must be CUDA");
    TORCH_CHECK(input.scalar_type() == at::kFloat, "layernorm_forward: only float32 supported");
    TORCH_CHECK(weight.scalar_type() == at::kFloat, "layernorm_forward: weight must be float32");
    TORCH_CHECK(bias.scalar_type() == at::kFloat, "layernorm_forward: bias must be float32");
    TORCH_CHECK(!normalized_shape.empty(), "layernorm_forward: normalized_shape must be non-empty");
    TORCH_CHECK(input.dim() >= static_cast<int64_t>(normalized_shape.size()),
                "layernorm_forward: input.dim < normalized_shape.size");

    // Validate trailing dimensions match normalized_shape
    auto in_sizes = input.sizes();
    int64_t k = static_cast<int64_t>(normalized_shape.size());
    for (int64_t i = 0; i < k; ++i) {
        TORCH_CHECK(in_sizes[in_sizes.size() - k + i] == normalized_shape[i],
                    "layernorm_forward: input trailing dims must match normalized_shape");
    }

    int64_t M = 1;
    for (int64_t d : normalized_shape) {
        TORCH_CHECK(d > 0, "layernorm_forward: normalized_shape dims must be > 0");
        M *= d;
    }
    TORCH_CHECK(weight.numel() == M, "layernorm_forward: weight numel mismatch");
    TORCH_CHECK(bias.numel() == M, "layernorm_forward: bias numel mismatch");

    auto input_c = input.contiguous();
    int64_t total = input_c.numel();
    TORCH_CHECK(total % M == 0, "layernorm_forward: input numel not divisible by M");
    int64_t B = total / M;

    auto x2d = input_c.view({B, M});
    auto w1d = weight.contiguous().view({M});
    auto b1d = bias.contiguous().view({M});

    auto options = input.options().dtype(at::kFloat);
    auto out2d = at::empty_like(x2d, options);
    auto mean = at::empty({B}, options);
    auto inv_std = at::empty({B}, options);

    // Choose threads per block: power-of-two between 256 and 1024, not exceeding M
    int t_candidate = (int)std::min<int64_t>(1024, (int64_t)next_pow2_int((int)std::min<int64_t>(M, 1024)));
    int threads = t_candidate < 256 ? 256 : t_candidate;
    int blocks = (int)B;
    int warp_count = (threads + KB_WARP_SIZE - 1) / KB_WARP_SIZE;
    size_t shmem = sizeof(float) * 2 * warp_count;

    rowwise_stats_kernel<<<blocks, threads, shmem, at::cuda::getCurrentCUDAStream()>>>(
        x2d.data_ptr<float>(),
        mean.data_ptr<float>(),
        inv_std.data_ptr<float>(),
        B, M, static_cast<float>(eps));

    layernorm_affine_kernel<<<blocks, threads, 0, at::cuda::getCurrentCUDAStream()>>>(
        x2d.data_ptr<float>(),
        w1d.data_ptr<float>(),
        b1d.data_ptr<float>(),
        mean.data_ptr<float>(),
        inv_std.data_ptr<float>(),
        out2d.data_ptr<float>(),
        B, M
    );

    auto out = out2d.view(input.sizes());
    return out;
}
""",
            functions=["layernorm_forward"],
            with_cuda=True,
            extra_cuda_cflags=["-O3"],
            extra_cflags=["-O3"],
            verbose=False,
        )
    except Exception:
        _kb_layernorm_mod = None
    return _kb_layernorm_mod


class ModelNew(nn.Module):
    """
    Drop-in replacement for Model that accelerates LayerNorm forward
    with a CUDA extension when beneficial, otherwise falls back to PyTorch.
    """
    def __init__(self, normalized_shape: tuple):
        super(ModelNew, self).__init__()
        self.ln = nn.LayerNorm(normalized_shape=normalized_shape)

        # Optionally warm up loader (will only build if CUDA is available)
        _get_kb_layernorm_mod()

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        # Only use custom CUDA path when:
        # - input is CUDA float32
        # - extension is available
        # - sufficiently large normalized dimension for payoff
        norm_shape = tuple(self.ln.normalized_shape)
        M = 1
        for d in norm_shape:
            M *= int(d)

        kb_mod = _get_kb_layernorm_mod()
        use_custom = (
            kb_mod is not None
            and x.is_cuda
            and x.dtype == torch.float32
            and M >= 512
            and x.numel() >= 100000
        )

        if use_custom:
            if getattr(self.ln, "elementwise_affine", True):
                weight = self.ln.weight
                bias = self.ln.bias
            else:
                # No affine: emulate with ones/zeros on the correct device
                weight = torch.ones(norm_shape, device=x.device, dtype=torch.float32)
                bias = torch.zeros(norm_shape, device=x.device, dtype=torch.float32)
            return kb_mod.layernorm_forward(
                x, weight, bias, float(self.ln.eps), list(norm_shape)
            )

        # Fallback to PyTorch reference
        return self.ln(x)

prompts.refiner_prompt:
You are the Refiner in an iterative optimization loop.

Objective:
Generate a complete, improved replacement of the previous candidate (prompt/code/patch) that reliably produces fast, correct CUDA kernels via torch.utils.cpp_extension.load_inline, integrated into a drop-in ModelNew that matches the reference model’s __init__ and forward signatures, preserves numerical correctness, and achieves speedup ≥ baseline.

Inputs each iteration:
- previous_candidate (string containing prompt/code/patch)
- error_feedback (error_type, error_detail)
- evaluation metrics (CompilationSucceeded, CorrectnessSucceeded, speedup, runtime_ms, logs, cuda_docs)

Outputs each iteration:
- A full replacement candidate that compiles, runs correctly, and improves performance or fixes issues. This can be a refined LLM prompt or an updated ModelNew implementation with extension code.

Non-negotiable constraints:
- ModelNew exists and matches the original Model’s __init__ signature and forward signature (drop-in).
- Correctness: outputs numerically match PyTorch reference within harness tolerance.
- Use torch.utils.cpp_extension.load_inline with:
  - cpp_sources: declarations only; DO NOT define PYBIND11_MODULE when using functions=[...].
  - cuda_sources: definitions and kernels.
  - functions: every function listed must have a matching declaration in cpp_sources.
  - Include headers: in both files #include <torch/extension.h>; in CUDA also #include <cuda_runtime.h> and #include <ATen/cuda/CUDAContext.h>.
  - Launch on PyTorch stream: kernel<<<blocks, threads, 0, at::cuda::getCurrentCUDAStream()>>>(...).
- No at::conv2d or other high-level ATen ops inside CUDA kernels. If you need those ops, call them in the C++ host function or in Python.
- No duplicate module init symbols or undefined symbols.
- Enforce contiguous tensors and exact shapes; handle dtype consistency (start with float32 unless required otherwise).
- Forward-only acceleration is sufficient unless explicitly required.

General refine algorithm (apply in this order):
1) Parse logs and status flags:
   - If CompilationSucceeded == False: treat as compilation failure and apply Fix-by-Pattern rules below.
   - Else if CorrectnessSucceeded == False: treat as correctness failure and apply Correctness repair rules below.
   - Else if speedup < 1.0: treat as performance regression and apply Performance improvements below.
   - Else: if speedup ≥ 1.0 and all checks pass, keep previous_candidate or make only minimal safe micro-optimizations (no risky structural changes).

2) Fix-by-Pattern (compilation failures):
   - Error mentions calling high-level ATen ops (e.g., at::conv2d) inside CUDA: remove such calls from cuda_sources; either implement the op properly as a kernel or move that call to Python/C++ host wrapper.
   - “CUDART_INF_F is undefined”: include <cuda_runtime.h> or use -INFINITY from <cmath>.
   - “multiple definition of PyInit_*”: ensure no PYBIND11_MODULE is present when using functions=[...]. cpp_sources should contain only function declarations; cuda_sources contains implementations.
   - “undefined symbol” for listed functions: verify identical name/signature exists in cpp_sources declaration and cuda_sources definition.
   - “cuda.h: No such file”: do not include <cuda.h>; include <cuda_runtime.h>.
   - “at::cuda has no member getCurrentCUDAStream”: add #include <ATen/cuda/CUDAContext.h>.
   - Python-side issues: ensure ModelNew is defined; helper functions return values; no syntax errors.

3) Correctness repair (shape, math, dtype):
   - Always call .contiguous() on inputs/weights/bias to match indexing.
   - Compute output dimensions carefully. For conv2d: Hout = (H + 2*pad_h - dil_h*(kH-1) - 1)/stride_h + 1; similarly for Wout; analogous for 3D if used.
   - Bias broadcast: bias[co] for 1D bias of size Cout or (Cout,1,1).
   - For reductions (e.g., LayerNorm, logsumexp), use numerically stable formulas (subtract max for exp sums; two-pass or Welford for mean/var).
   - Keep dtype consistent (start with float32); cast to float for accumulation if reading other types, then cast back.
   - Ensure forward returns exactly the same shapes as reference.

4) Performance improvements (if correct but slow):
   - Fuse obvious chains to reduce memory traffic:
     - Conv2d + Bias + ReLU: single fused kernel (template provided below).
     - GEMM + per-output scale: fused in one kernel with shared-memory tiling (template below). Keep BatchNorm in PyTorch unless you implement a correct two-pass BN; BN fusion is optional and complex.
     - LayerNorm: two-kernel forward (mean/var then normalize) with one block per row (template below).
     - Mean reduction across non-batch dims: per-batch reduction kernel (template below).
   - Enforce contiguity; pick threads per block in [128, 256] commonly; grid = ceil(numel / threads) or 2D grid for tiles.
   - Use coalesced global memory access, flat indexing or grid-stride loops; avoid extra synchronizations.
   - Consider simple tiling with shared memory for GEMM-like ops (TILE_M/N/K with 16x16 threads); multiply by scale before writing out.
   - Do not overcomplicate; start with correct simple fused kernel and iterate.

5) Integration rules:
   - Wrap extension loading in a helper to compile once and cache the module. Use a unique, stable name per op family to avoid collisions.
   - Only use the CUDA path when inputs are CUDA tensors; otherwise fallback to PyTorch ops.
   - ModelNew must reuse original weights/params and produce identical outputs.
   - Keep gradients out unless required; forward-only is fine.

Decision heuristics by model pattern (use logs, code inspection, or cuda_docs to decide):
- Pattern: Linear/GEMM + Scale (+ optional BatchNorm1d)
  Strategy: Implement fused tiled GEMM + scale kernel; keep BN in PyTorch.
  Use template: GEMM+Scale (kb_gemm_scale_forward) below.
- Pattern: Conv2d + Bias + ReLU
  Strategy: Use fused conv2d+bias+relu kernel. Use the provided minimal reliable template (conv2d_bias_relu_forward) below.
- Pattern: LayerNorm
  Strategy: Two-kernel LayerNorm forward (compute per-row mean/var, then normalize+affine). Use template below.
- Pattern: Conv3d + GroupNorm + final mean reduction
  Strategy: Keep Conv3d and GroupNorm in PyTorch; implement a custom per-batch mean reduction kernel over dims [1,2,3,4] to reduce overhead. Use template below.

When to preserve existing behaviors:
- If a prior iteration already achieved correctness and speedup ≥ 1 across a pattern (e.g., LayerNorm), retain that approach and avoid risky changes.
- Only touch the slowest segments: add a fused kernel where you can safely replicate the math exactly.

Deliverable structure to generate (replace the previous candidate with this):
- A single Python file content containing:
  - ModelNew class matching Model’s __init__ and forward.
  - An extension loader (cached) implementing only the kernels you need for this model.
  - Clean load_inline usage per constraints.
  - Fallback logic to PyTorch ops on CPU or if extension is unavailable.

Copy-ready load_inline templates (adapt verbatim; keep names/signatures consistent)

1) Fused Conv2d + Bias + ReLU (float32)
- Use when the reference does conv2d -> add bias -> relu in forward.

Python loader usage (inside your file):
module = load_inline(
    name="kb_conv2d_bias_relu",
    cpp_sources=r"""
#include <torch/extension.h>
torch::Tensor conv2d_bias_relu_forward(torch::Tensor x, torch::Tensor w, torch::Tensor b,
                                       int64_t stride_h, int64_t stride_w,
                                       int64_t pad_h, int64_t pad_w,
                                       int64_t dil_h, int64_t dil_w);
""",
    cuda_sources=r"""
#include <torch/extension.h>
#include <cuda_runtime.h>
#include <ATen/cuda/CUDAContext.h>

template <typename T>
__global__ void conv2d_bias_relu_kernel(
    const T* __restrict__ x, const T* __restrict__ w, const T* __restrict__ b,
    T* __restrict__ y,
    int N, int Cin, int H, int W,
    int Cout, int kH, int kW,
    int Hout, int Wout,
    int stride_h, int stride_w,
    int pad_h, int pad_w,
    int dil_h, int dil_w) {
  int idx = blockIdx.x * blockDim.x + threadIdx.x;
  int total = N * Cout * Hout * Wout;
  if (idx >= total) return;

  int w_out = idx % Wout;
  int tmp = idx / Wout;
  int h_out = tmp % Hout;
  tmp /= Hout;
  int co = tmp % Cout;
  int n = tmp / Cout;

  float acc = 0.f;
  int h_in0 = h_out * stride_h - pad_h;
  int w_in0 = w_out * stride_w - pad_w;

  for (int ci = 0; ci < Cin; ++ci) {
    for (int kh = 0; kh < kH; ++kh) {
      int h_in = h_in0 + kh * dil_h;
      if ((unsigned)h_in >= (unsigned)H) continue;
      for (int kw = 0; kw < kW; ++kw) {
        int w_in = w_in0 + kw * dil_w;
        if ((unsigned)w_in >= (unsigned)W) continue;
        int x_idx = ((n * Cin + ci) * H + h_in) * W + w_in;
        int w_idx = ((co * Cin + ci) * kH + kh) * kW + kw;
        acc += static_cast<float>(x[x_idx]) * static_cast<float>(w[w_idx]);
      }
    }
  }
  acc += static_cast<float>(b[co]);
  acc = acc > 0.f ? acc : 0.f;
  y[idx] = static_cast<T>(acc);
}

torch::Tensor conv2d_bias_relu_forward(torch::Tensor x, torch::Tensor w, torch::Tensor b,
                                       int64_t stride_h, int64_t stride_w,
                                       int64_t pad_h, int64_t pad_w,
                                       int64_t dil_h, int64_t dil_w) {
  TORCH_CHECK(x.is_cuda() && w.is_cuda() && b.is_cuda(), "All tensors must be CUDA");
  TORCH_CHECK(x.scalar_type() == at::kFloat, "Only float32 is supported");
  auto x_c = x.contiguous();
  auto w_c = w.contiguous();
  auto b_c = b.contiguous();

  int64_t N = x_c.size(0), Cin = x_c.size(1), H = x_c.size(2), W = x_c.size(3);
  int64_t Cout = w_c.size(0), kH = w_c.size(2), kW = w_c.size(3);

  int64_t Hout = (H + 2 * pad_h - dil_h * (kH - 1) - 1) / stride_h + 1;
  int64_t Wout = (W + 2 * pad_w - dil_w * (kW - 1) - 1) / stride_w + 1;

  auto y = torch::empty({N, Cout, Hout, Wout}, x_c.options());

  int64_t total = N * Cout * Hout * Wout;
  int threads = 256;
  int blocks = (total + threads - 1) / threads;

  conv2d_bias_relu_kernel<float><<<blocks, threads, 0, at::cuda::getCurrentCUDAStream()>>>(
      x_c.data_ptr<float>(), w_c.data_ptr<float>(), b_c.data_ptr<float>(),
      y.data_ptr<float>(),
      (int)N, (int)Cin, (int)H, (int)W,
      (int)Cout, (int)kH, (int)kW,
      (int)Hout, (int)Wout,
      (int)stride_h, (int)stride_w,
      (int)pad_h, (int)pad_w,
      (int)dil_h, (int)dil_w);

  return y;
}
""",
    functions=["conv2d_bias_relu_forward"],
    verbose=False
)

2) Fused GEMM + per-output scale (float32, shared-memory tiled)
- Use when the model does Y = (X @ W.t()) * scale; keep BatchNorm in PyTorch for simplicity.

module = load_inline(
    name="kb_gemm_scale",
    cpp_sources=r"""
#include <torch/extension.h>
torch::Tensor kb_gemm_scale_forward(torch::Tensor X, torch::Tensor W, torch::Tensor scale);
""",
    cuda_sources=r"""
#include <torch/extension.h>
#include <cuda_runtime.h>
#include <ATen/cuda/CUDAContext.h>

#define TILE_M 16
#define TILE_N 16
#define TILE_K 32

__global__ void gemm_scale_kernel(
    const float* __restrict__ X,   // [N, K]
    const float* __restrict__ W,   // [O, K] (access as W[o*K + k])
    const float* __restrict__ S,   // [O]
    float* __restrict__ Y,         // [N, O]
    int N, int K, int O) {

  __shared__ float As[TILE_M][TILE_K];
  __shared__ float Bs[TILE_K][TILE_N];

  int block_m = blockIdx.y * TILE_M;
  int block_n = blockIdx.x * TILE_N;

  int tm = threadIdx.y;
  int tn = threadIdx.x;

  int row = block_m + tm;
  int col = block_n + tn;

  float acc = 0.f;

  for (int kk = 0; kk < K; kk += TILE_K) {
    // Load A tile (X)
    if (row < N) {
      int k_load = kk + tn;
      As[tm][tn] = (k_load < K) ? X[row * K + k_load] : 0.f;
    } else {
      As[tm][tn] = 0.f;
    }

    // Load B tile (W as [O, K], we need W^T => index W[o, k])
    if (col < O) {
      int k_load = kk + tm;
      Bs[tm][tn] = (k_load < K) ? W[col * K + k_load] : 0.f;
    } else {
      Bs[tm][tn] = 0.f;
    }

    __syncthreads();

    #pragma unroll
    for (int k = 0; k < TILE_K; ++k) {
      acc += As[tm][k] * Bs[k][tn];
    }
    __syncthreads();
  }

  if (row < N && col < O) {
    float scaled = acc * S[col];
    Y[row * O + col] = scaled;
  }
}

torch::Tensor kb_gemm_scale_forward(torch::Tensor X, torch::Tensor W, torch::Tensor scale) {
  TORCH_CHECK(X.is_cuda() && W.is_cuda() && scale.is_cuda(), "All tensors must be CUDA");
  TORCH_CHECK(X.scalar_type() == at::kFloat && W.scalar_type() == at::kFloat && scale.scalar_type() == at::kFloat,
              "Only float32 is supported");
  auto Xc = X.contiguous();
  auto Wc = W.contiguous();   // [O, K]
  auto Sc = scale.contiguous(); // [O]

  int N = (int)Xc.size(0);
  int K = (int)Xc.size(1);
  TORCH_CHECK(Wc.dim() == 2 && Wc.size(1) == K, "W must be [O, K]");
  int O = (int)Wc.size(0);
  TORCH_CHECK(Sc.numel() == O, "scale must have length O");

  auto Y = torch::empty({N, O}, Xc.options());

  dim3 block(TILE_N, TILE_M);
  dim3 grid((O + TILE_N - 1) / TILE_N, (N + TILE_M - 1) / TILE_M);

  gemm_scale_kernel<<<grid, block, 0, at::cuda::getCurrentCUDAStream()>>>(
      Xc.data_ptr<float>(),
      Wc.data_ptr<float>(),
      Sc.data_ptr<float>(),
      Y.data_ptr<float>(),
      N, K, O);

  return Y;
}
""",
    functions=["kb_gemm_scale_forward"],
    verbose=False
)

3) LayerNorm forward (two-kernel, float32)
- Normalize over trailing normalized_shape; flatten to [B, M].

module = load_inline(
    name="kb_layernorm",
    cpp_sources=r"""
#include <torch/extension.h>
torch::Tensor kb_layernorm_forward(torch::Tensor x2d, torch::Tensor weight, torch::Tensor bias, double eps);
""",
    cuda_sources=r"""
#include <torch/extension.h>
#include <cuda_runtime.h>
#include <ATen/cuda/CUDAContext.h>

__global__ void row_stats_kernel(const float* __restrict__ x, float* __restrict__ mean, float* __restrict__ var,
                                 int B, int M) {
  extern __shared__ float smem[];
  float* ssum = smem;
  float* ssum2 = smem + blockDim.x;

  int row = blockIdx.x;
  if (row >= B) return;

  float local_sum = 0.f;
  float local_sum2 = 0.f;
  for (int j = threadIdx.x; j < M; j += blockDim.x) {
    float v = x[row * M + j];
    local_sum += v;
    local_sum2 += v * v;
  }

  ssum[threadIdx.x] = local_sum;
  ssum2[threadIdx.x] = local_sum2;
  __syncthreads();

  // reduce
  for (int stride = blockDim.x / 2; stride > 0; stride >>= 1) {
    if (threadIdx.x < stride) {
      ssum[threadIdx.x] += ssum[threadIdx.x + stride];
      ssum2[threadIdx.x] += ssum2[threadIdx.x + stride];
    }
    __syncthreads();
  }

  if (threadIdx.x == 0) {
    float m = ssum[0] / M;
    float v = ssum2[0] / M - m * m;
    mean[row] = m;
    var[row] = v;
  }
}

__global__ void layernorm_apply_kernel(const float* __restrict__ x, const float* __restrict__ mean,
                                       const float* __restrict__ var, const float* __restrict__ w,
                                       const float* __restrict__ b, float* __restrict__ y,
                                       int B, int M, float eps) {
  int row = blockIdx.x;
  if (row >= B) return;
  float m = mean[row];
  float inv_std = rsqrtf(var[row] + eps);

  for (int j = threadIdx.x; j < M; j += blockDim.x) {
    float xn = (x[row * M + j] - m) * inv_std;
    float out = xn * (w ? w[j] : 1.f) + (b ? b[j] : 0.f);
    y[row * M + j] = out;
  }
}

torch::Tensor kb_layernorm_forward(torch::Tensor x2d, torch::Tensor weight, torch::Tensor bias, double eps) {
  TORCH_CHECK(x2d.is_cuda(), "x must be CUDA");
  TORCH_CHECK(x2d.scalar_type() == at::kFloat, "Only float32 is supported");
  auto X = x2d.contiguous();
  float* wptr = nullptr;
  float* bptr = nullptr;

  int B = (int)X.size(0);
  int M = (int)X.size(1);

  auto Y = torch::empty_like(X);
  auto mean = torch::empty({B}, X.options());
  auto var = torch::empty({B}, X.options());

  if (weight.defined() && weight.numel() == M) wptr = weight.contiguous().data_ptr<float>();
  if (bias.defined() && bias.numel() == M) bptr = bias.contiguous().data_ptr<float>();

  int threads = 256;
  row_stats_kernel<<<B, threads, sizeof(float) * threads * 2, at::cuda::getCurrentCUDAStream()>>>(
      X.data_ptr<float>(), mean.data_ptr<float>(), var.data_ptr<float>(), B, M);

  layernorm_apply_kernel<<<B, threads, 0, at::cuda::getCurrentCUDAStream()>>>(
      X.data_ptr<float>(), mean.data_ptr<float>(), var.data_ptr<float>(),
      wptr, bptr, Y.data_ptr<float>(), B, M, (float)eps);

  return Y;
}
""",
    functions=["kb_layernorm_forward"],
    verbose=False
)

4) Per-batch mean reduction over non-batch dims (float32)
- Use when model ends with x.mean(dim=[1,2,3,4]) or similar.

module = load_inline(
    name="kb_reduce_mean_nb",
    cpp_sources=r"""
#include <torch/extension.h>
torch::Tensor kb_reduce_mean_nonbatch(torch::Tensor x);
""",
    cuda_sources=r"""
#include <torch/extension.h>
#include <cuda_runtime.h>
#include <ATen/cuda/CUDAContext.h>

__global__ void reduce_mean_nb_kernel(const float* __restrict__ x, float* __restrict__ out,
                                      int N, int inner) {
  extern __shared__ float smem[];
  int n = blockIdx.x;
  float sum = 0.f;
  for (int i = threadIdx.x; i < inner; i += blockDim.x) {
    sum += x[n * inner + i];
  }
  smem[threadIdx.x] = sum;
  __syncthreads();
  for (int s = blockDim.x >> 1; s > 0; s >>= 1) {
    if (threadIdx.x < s) smem[threadIdx.x] += smem[threadIdx.x + s];
    __syncthreads();
  }
  if (threadIdx.x == 0) {
    out[n] = smem[0] / inner;
  }
}

torch::Tensor kb_reduce_mean_nonbatch(torch::Tensor x) {
  TORCH_CHECK(x.is_cuda(), "x must be CUDA");
  TORCH_CHECK(x.scalar_type() == at::kFloat, "Only float32 is supported");
  auto xc = x.contiguous();
  int64_t N = xc.size(0);
  int64_t inner = 1;
  for (int i = 1; i < xc.dim(); ++i) inner *= xc.size(i);
  auto flat = xc.view({N, inner});
  auto out = torch::empty({N}, xc.options());
  int threads = 256;
  reduce_mean_nb_kernel<<<N, threads, sizeof(float)*threads, at::cuda::getCurrentCUDAStream()>>>(
      flat.data_ptr<float>(), out.data_ptr<float>(), (int)N, (int)inner);
  return out;
}
""",
    functions=["kb_reduce_mean_nonbatch"],
    verbose=False
)

