# Complete, self-contained Python file implementing ModelNew with a CUDA-accelerated MaxPool2d forward,
# built via torch.utils.cpp_extension.load_inline. Includes an optimized shared-memory kernel for stride=1,dilation=1,
# and a generic fallback kernel. Falls back to PyTorch for non-float32/CPU/small cases.

import math
from typing import Any, List

import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

# Build the CUDA extension once at import time
cpp_src = r"""
#include <torch/extension.h>

// Forward declaration (exposed to Python)
torch::Tensor maxpool2d_forward(torch::Tensor input, int kernel_size, int stride, int padding, int dilation);
"""

cuda_src = r"""
#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>
#include <cuda_runtime.h>
#include <float.h>

// Generic per-output-element maxpool (supports dilation/stride/padding)
template <typename T>
__global__ void maxpool2d_forward_kernel_generic(
    const T* __restrict__ input,
    T* __restrict__ output,
    int N, int C, int H_in, int W_in,
    int H_out, int W_out,
    int kernel_size, int stride, int padding, int dilation
) {
    long long total = (long long)N * C * H_out * W_out;
    long long idx = blockIdx.x * (long long)blockDim.x + threadIdx.x;
    if (idx >= total) return;

    // Decompose linear index to (n, c, h_out, w_out)
    int w_out_idx = (int)(idx % W_out);
    long long tmp = idx / W_out;
    int h_out_idx = (int)(tmp % H_out);
    tmp /= H_out;
    int c = (int)(tmp % C);
    int n = (int)(tmp / C);

    int h_start = h_out_idx * stride - padding;
    int w_start = w_out_idx * stride - padding;

    T maxval = (T)(-FLT_MAX);

    // Iterate over pooling window with dilation
    for (int kh = 0; kh < kernel_size; ++kh) {
        int h_in = h_start + kh * dilation;
        if ((unsigned)h_in >= (unsigned)H_in) continue;
        for (int kw = 0; kw < kernel_size; ++kw) {
            int w_in = w_start + kw * dilation;
            if ((unsigned)w_in >= (unsigned)W_in) continue;

            long long in_off = (((long long)n * C + c) * H_in + h_in) * W_in + w_in;
            T v = input[in_off];
            maxval = v > maxval ? v : maxval;
        }
    }

    long long out_off = (((long long)n * C + c) * H_out + h_out_idx) * W_out + w_out_idx;
    output[out_off] = maxval;
}

// Optimized shared-memory tiled kernel for stride=1, dilation=1
// Each block computes a tile of output for a single (n,c).
template <typename T>
__global__ void maxpool2d_forward_kernel_tiled_s1d1(
    const T* __restrict__ input,
    T* __restrict__ output,
    int N, int C, int H_in, int W_in,
    int H_out, int W_out,
    int kernel_size, int padding
) {
    // Block maps to single (n,c)
    int nc = blockIdx.z;
    int n = nc / C;
    int c = nc % C;

    // Output tile origin (top-left) in output coords
    int h_out_tile = blockIdx.y * blockDim.y;
    int w_out_tile = blockIdx.x * blockDim.x;

    // Corresponding input tile origin (considering padding)
    int h_in_tile = h_out_tile - padding;
    int w_in_tile = w_out_tile - padding;

    // Shared memory tile dims
    int tileH = blockDim.y + kernel_size - 1;
    int tileW = blockDim.x + kernel_size - 1;

    extern __shared__ T smem[]; // size tileH * tileW
    // Load input tile with halo into shared memory
    for (int th = threadIdx.y; th < tileH; th += blockDim.y) {
        int h_in = h_in_tile + th;
        bool h_valid = (unsigned)h_in < (unsigned)H_in;
        for (int tw = threadIdx.x; tw < tileW; tw += blockDim.x) {
            int w_in = w_in_tile + tw;
            bool w_valid = (unsigned)w_in < (unsigned)W_in;
            T val = (T)(-FLT_MAX);
            if (h_valid && w_valid) {
                long long in_off = (((long long)n * C + c) * H_in + h_in) * W_in + w_in;
                val = input[in_off];
            }
            smem[th * tileW + tw] = val;
        }
    }
    __syncthreads();

    // Compute output value per thread
    int h_out = h_out_tile + threadIdx.y;
    int w_out = w_out_tile + threadIdx.x;
    if (h_out < H_out && w_out < W_out) {
        T m = (T)(-FLT_MAX);
        // Window entirely fits within smem by construction
        #pragma unroll
        for (int kh = 0; kh < 7; ++kh) {
            if (kh >= kernel_size) break;
            #pragma unroll
            for (int kw = 0; kw < 7; ++kw) {
                if (kw >= kernel_size) break;
                T v = smem[(threadIdx.y + kh) * tileW + (threadIdx.x + kw)];
                m = v > m ? v : m;
            }
        }
        long long out_off = (((long long)n * C + c) * H_out + h_out) * W_out + w_out;
        output[out_off] = m;
    }
}

static inline void launch_checked(cudaError_t err, const char* msg) {
    if (err != cudaSuccess) {
        TORCH_CHECK(false, msg, " (", cudaGetErrorString(err), ")");
    }
}

torch::Tensor maxpool2d_forward(torch::Tensor input, int kernel_size, int stride, int padding, int dilation) {
    TORCH_CHECK(input.is_cuda(), "maxpool2d_forward: input must be a CUDA tensor");
    TORCH_CHECK(input.dim() == 4, "maxpool2d_forward: input must be 4D NCHW");
    TORCH_CHECK(input.scalar_type() == at::kFloat, "maxpool2d_forward: only float32 supported");
    TORCH_CHECK(kernel_size >= 1, "maxpool2d_forward: kernel_size must be >= 1");
    TORCH_CHECK(stride >= 1, "maxpool2d_forward: stride must be >= 1");
    TORCH_CHECK(dilation >= 1, "maxpool2d_forward: dilation must be >= 1");
    TORCH_CHECK(padding >= 0, "maxpool2d_forward: padding must be >= 0");

    auto x = input.contiguous();
    const int64_t N = x.size(0);
    const int64_t C = x.size(1);
    const int64_t H_in = x.size(2);
    const int64_t W_in = x.size(3);

    // Output dimensions (ceil_mode = False)
    int64_t H_out = (H_in + 2 * (int64_t)padding - (int64_t)dilation * (kernel_size - 1) - 1) / (int64_t)stride + 1;
    int64_t W_out = (W_in + 2 * (int64_t)padding - (int64_t)dilation * (kernel_size - 1) - 1) / (int64_t)stride + 1;
    TORCH_CHECK(H_out >= 0 && W_out >= 0, "maxpool2d_forward: computed non-positive output size");

    auto out = torch::empty({N, C, H_out, W_out}, x.options());

    if (H_out == 0 || W_out == 0) {
        return out; // nothing to compute
    }

    const float* in_ptr = x.data_ptr<float>();
    float* out_ptr = out.data_ptr<float>();

    cudaStream_t stream = at::cuda::getCurrentCUDAStream();

    // Choose optimized kernel when beneficial: stride=1, dilation=1, small kernel (<=7)
    if (stride == 1 && dilation == 1 && kernel_size <= 7) {
        dim3 threads(16, 16, 1);
        dim3 blocks((int)((W_out + threads.x - 1) / threads.x),
                    (int)((H_out + threads.y - 1) / threads.y),
                    (int)(N * C));
        int tileH = threads.y + kernel_size - 1;
        int tileW = threads.x + kernel_size - 1;
        size_t smem_bytes = (size_t)tileH * (size_t)tileW * sizeof(float);

        maxpool2d_forward_kernel_tiled_s1d1<float>
            <<<blocks, threads, smem_bytes, stream>>>(
                in_ptr, out_ptr,
                (int)N, (int)C, (int)H_in, (int)W_in,
                (int)H_out, (int)W_out,
                kernel_size, padding
            );
        launch_checked(cudaGetLastError(), "maxpool2d_forward: tiled kernel launch failed");
    } else {
        long long total = (long long)N * C * H_out * W_out;
        int threads = 256;
        int blocks = (int)((total + threads - 1LL) / threads);
        maxpool2d_forward_kernel_generic<float>
            <<<blocks, threads, 0, stream>>>(
                in_ptr, out_ptr,
                (int)N, (int)C, (int)H_in, (int)W_in,
                (int)H_out, (int)W_out,
                kernel_size, stride, padding, dilation
            );
        launch_checked(cudaGetLastError(), "maxpool2d_forward: generic kernel launch failed");
    }

    return out;
}
"""

# Build and cache the extension
kb_ext = load_inline(
    name="kb_maxpool2d_ext",
    cpp_sources=cpp_src,
    cuda_sources=cuda_src,
    functions=["maxpool2d_forward"],
    with_cuda=True,
    verbose=False,
    extra_cuda_cflags=["-O3"],
    extra_cflags=["-O3"],
)

class ModelNew(nn.Module):
    """
    Drop-in replacement for Model that accelerates MaxPool2d forward with a CUDA extension
    when inputs are float32 CUDA tensors. Falls back to PyTorch otherwise.
    Matches Model's __init__ and forward signatures.
    """
    def __init__(self, kernel_size: int, stride: int, padding: int, dilation: int):
        super(ModelNew, self).__init__()
        # Keep a reference PyTorch layer for fallback and parity
        self.maxpool_ref = nn.MaxPool2d(
            kernel_size=kernel_size,
            stride=stride,
            padding=padding,
            dilation=dilation,
        )
        # Store parameters (ints) for extension path
        self.kernel_size = int(kernel_size)
        self.stride = int(stride)
        self.padding = int(padding)
        self.dilation = int(dilation)

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        # Use custom kernel only for float32 CUDA tensors
        use_ext = (
            x.is_cuda
            and x.dtype == torch.float32
            and isinstance(self.kernel_size, int)
            and isinstance(self.stride, int)
            and isinstance(self.padding, int)
            and isinstance(self.dilation, int)
        )
        # Optional heuristic: for extremely small problems, launch overhead may dominate; let PyTorch handle it
        if use_ext:
            H_in, W_in = x.shape[-2], x.shape[-1]
            H_out = (H_in + 2 * self.padding - self.dilation * (self.kernel_size - 1) - 1) // self.stride + 1
            W_out = (W_in + 2 * self.padding - self.dilation * (self.kernel_size - 1) - 1) // self.stride + 1
            total_out = x.shape[0] * x.shape[1] * max(H_out, 0) * max(W_out, 0)
            if total_out < 100_000:  # small size guard
                use_ext = False

        if use_ext:
            # Ensure contiguous memory for predictable indexing
            x_in = x.contiguous()
            return kb_ext.maxpool2d_forward(
                x_in,
                int(self.kernel_size),
                int(self.stride),
                int(self.padding),
                int(self.dilation),
            )
        else:
            # Fallback to PyTorch reference op (supports all dtypes/devices)
            return self.maxpool_ref(x)


# Minimal harness for local quick test (optional)
if __name__ == "__main__":
    # Compare against PyTorch for correctness
    batch_size = 2
    channels = 3
    height = 32
    width = 35
    kernel_size = 4
    stride = 1
    padding = 1
    dilation = 1

    model_ref = nn.Sequential(nn.MaxPool2d(kernel_size, stride, padding, dilation)).eval()
    model_new = ModelNew(kernel_size, stride, padding, dilation).eval()

    for device in ["cpu"] + (["cuda"] if torch.cuda.is_available() else []):
        x = torch.randn(batch_size, channels, height, width, device=device, dtype=torch.float32)
        with torch.no_grad():
            y_ref = model_ref(x)
            y_new = model_new(x)
        max_abs = (y_ref - y_new).abs().max().item()
        print(f"Device {device}: max abs diff = {max_abs:.6g}, shapes {y_ref.shape} vs {y_new.shape}")
        assert y_ref.shape == y_new.shape
        if device == "cuda":
            assert max_abs == 0.0 or max_abs < 1e-6, "CUDA extension output mismatch"
        else:
            # CPU path uses PyTorch reference anyway
