      name="kb_ext_convtranspose3d",
      cpp_sources=r"""
#include <torch/extension.h>
torch::Tensor conv_transpose3d_bias_forward(torch::Tensor x, torch::Tensor w, torch::Tensor b,
                                            int64_t stride_d, int64_t stride_h, int64_t stride_w,
                                            int64_t pad_d, int64_t pad_h, int64_t pad_w,
                                            int64_t dil_d, int64_t dil_h, int64_t dil_w);

torch::Tensor conv_transpose3d_bias_relu_forward(torch::Tensor x, torch::Tensor w, torch::Tensor b,
                                                 int64_t stride_d, int64_t stride_h, int64_t stride_w,
                                                 int64_t pad_d, int64_t pad_h, int64_t pad_w,
                                                 int64_t dil_d, int64_t dil_h, int64_t dil_w);
""",
      cuda_sources=r"""
#include <torch/extension.h>
#include <cuda_runtime.h>
#include <ATen/cuda/CUDAContext.h>
#include <cmath>

template <typename T, bool FuseReLU>
__global__ void convtranspose3d_bias_kernel(
    const T* __restrict__ x,      // (N, Cin, Di, Hi, Wi)
    const T* __restrict__ w,      // (Cin, Cout, kD, kH, kW)
    const T* __restrict__ b,      // (Cout)
    T* __restrict__ y,            // (N, Cout, Do, Ho, Wo)
    int N, int Cin, int Di, int Hi, int Wi,
    int Cout, int kD, int kH, int kW,
    int Do, int Ho, int Wo,
    int stride_d, int stride_h, int stride_w,
    int pad_d, int pad_h, int pad_w,
    int dil_d, int dil_h, int dil_w) {

  int idx = blockIdx.x * blockDim.x + threadIdx.x;
  int total = N * Cout * Do * Ho * Wo;
  if (idx >= total) return;

  int ow = idx % Wo;
  int tmp = idx / Wo;
  int oh = tmp % Ho;
  tmp /= Ho;
  int od = tmp % Do;
  tmp /= Do;
  int oc = tmp % Cout;
  int n  = tmp / Cout;

  float acc = 0.f;

  // For each input channel and kernel offset, compute contributing input index if divisible by stride and in bounds
  for (int ic = 0; ic < Cin; ++ic) {
    for (int kd = 0; kd < kD; ++kd) {
      int id_num = od + pad_d - kd * dil_d;
      if (id_num < 0) continue;
      if (id_num % stride_d != 0) continue;
      int id = id_num / stride_d;
      if ((unsigned)id >= (unsigned)Di) continue;

      for (int kh = 0; kh < kH; ++kh) {
        int ih_num = oh + pad_h - kh * dil_h;
        if (ih_num < 0) continue;
        if (ih_num % stride_h != 0) continue;
        int ih = ih_num / stride_h;
        if ((unsigned)ih >= (unsigned)Hi) continue;

        for (int kw = 0; kw < kW; ++kw) {
          int iw_num = ow + pad_w - kw * dil_w;
          if (iw_num < 0) continue;
          if (iw_num % stride_w != 0) continue;
          int iw = iw_num / stride_w;
          if ((unsigned)iw >= (unsigned)Wi) continue;

          int x_idx = (((n * Cin + ic) * Di + id) * Hi + ih) * Wi + iw;
          int w_idx = ((((ic * Cout) + oc) * kD + kd) * kH + kh) * kW + kw;
          acc += static_cast<float>(x[x_idx]) * static_cast<float>(w[w_idx]);
        }
      }
    }
  }

  acc += static_cast<float>(b[oc]);
  if (FuseReLU) acc = acc > 0.f ? acc : 0.f;

  int y_idx = (((n * Cout + oc) * Do + od) * Ho + oh) * Wo + ow;
  y[y_idx] = static_cast<T>(acc);
}

static inline void check_inputs_ct3d(const at::Tensor& x, const at::Tensor& w, const at::Tensor& b) {
  TORCH_CHECK(x.is_cuda() && w.is_cuda() && b.is_cuda(), "All tensors must be CUDA");
  TORCH_CHECK(x.scalar_type() == at::kFloat, "Only float32 is supported initially");
  TORCH_CHECK(x.dim() == 5 && w.dim() == 5, "x and w must be 5D (N,C,D,H,W) and (Cin,Cout,kD,kH,kW)");
  TORCH_CHECK(b.dim() == 1 && b.size(0) == w.size(1), "bias shape must be (Cout)");
  TORCH_CHECK(x.size(1) == w.size(0), "Cin mismatch between x and w");
}

template <bool FuseReLU>
torch::Tensor ct3d_impl(torch::Tensor x, torch::Tensor w, torch::Tensor b,
                        int64_t stride_d, int64_t stride_h, int64_t stride_w,
                        int64_t pad_d, int64_t pad_h, int64_t pad_w,
                        int64_t dil_d, int64_t dil_h, int64_t dil_w) {
  check_inputs_ct3d(x, w, b);
  auto x_c = x.contiguous(), w_c = w.contiguous(), b_c = b.contiguous();

  int64_t N = x_c.size(0), Cin = x_c.size(1), Di = x_c.size(2), Hi = x_c.size(3), Wi = x_c.size(4);
  int64_t CinW = w_c.size(0), Cout = w_c.size(1), kD = w_c.size(2), kH = w_c.size(3), kW = w_c.size(4);
  TORCH_CHECK(Cin == CinW, "Input channels mismatch");

  int64_t Do = (Di - 1) * stride_d - 2 * pad_d + dil_d * (kD - 1) + 1;
  int64_t Ho = (Hi - 1) * stride_h - 2 * pad_h + dil_h * (kH - 1) + 1;
  int64_t Wo = (Wi - 1) * stride_w - 2 * pad_w + dil_w * (kW - 1) + 1;
  TORCH_CHECK(Do > 0 && Ho > 0 && Wo > 0, "Computed output size must be positive");

  auto y = torch::empty({N, Cout, Do, Ho, Wo}, x_c.options());

  int64_t total = N * Cout * Do * Ho * Wo;
  int threads = 256;
  int blocks = (total + threads - 1) / threads;

  if (FuseReLU) {
    convtranspose3d_bias_kernel<float, true><<<blocks, threads, 0, at::cuda::getCurrentCUDAStream()>>>(
      x_c.data_ptr<float>(), w_c.data_ptr<float>(), b_c.data_ptr<float>(),
      y.data_ptr<float>(),
      (int)N, (int)Cin, (int)Di, (int)Hi, (int)Wi,
      (int)Cout, (int)kD, (int)kH, (int)kW,
      (int)Do, (int)Ho, (int)Wo,
      (int)stride_d, (int)stride_h, (int)stride_w,
      (int)pad_d, (int)pad_h, (int)pad_w,
      (int)dil_d, (int)dil_h, (int)dil_w);
  } else {
    convtranspose3d_bias_kernel<float, false><<<blocks, threads, 0, at::cuda::getCurrentCUDAStream()>>>(
      x_c.data_ptr<float>(), w_c.data_ptr<float>(), b_c.data_ptr<float>(),
      y.data_ptr<float>(),
      (int)N, (int)Cin, (int)Di, (int)Hi, (int)Wi,
      (int)Cout, (int)kD, (int)kH, (int)kW,
      (int)Do, (int)Ho, (int)Wo,
      (int)stride_d, (int)stride_h, (int)stride_w,
      (int)pad_d, (int)pad_h, (int)pad_w,
      (int)dil_d, (int)dil_h, (int)dil_w);
  }

  return y;
}

torch::Tensor conv_transpose3d_bias_forward(torch::Tensor x, torch::Tensor w, torch::Tensor b,
                                            int64_t stride_d, int64_t stride_h, int64_t stride_w,
                                            int64_t pad_d, int64_t pad_h, int64_t pad_w,
                                            int64_t dil_d, int64_t dil_h, int64_t dil_w) {
  return ct3d_impl<false>(x, w, b, stride_d, stride_h, stride_w, pad_d, pad_h, pad_w, dil_d, dil_h, dil_w);
}

torch::Tensor conv_transpose3d_bias_relu_forward(torch::Tensor x, torch::Tensor w, torch::Tensor b,
                                                 int64_t stride_d, int64_t stride_h, int64_t stride_w,
                                                 int64_t pad_d, int64_t pad_h, int64_t pad_w,
                                                 int64_t dil_d, int64_t dil_h, int64_t dil_w) {
  return ct3d_impl<true>(x, w, b, stride_d, stride_h, stride_w, pad_d, pad_h, pad_w, dil_d, dil_h, dil_w);
}
""",
      functions=["conv_transpose3d_bias_forward", "conv_transpose3d_bias_relu_forward"],
      verbose=False
  )

C) Fused linear + reductions (for models with Linear + sum/max/mean/logsumexp collapsible to GEMV):
- Algebraic fusion: out[i] = dot(input[i], weight.sum(dim=0)) + bias.sum(), shape (B,1).

  module_linred = load_inline(
      name="kb_ext_fused_linred",
      cpp_sources=r"""
#include <torch/extension.h>
torch::Tensor fused_linear_sum(torch::Tensor x, torch::Tensor w, torch::Tensor b);
""",
      cuda_sources=r"""
#include <torch/extension.h>
#include <cuda_runtime.h>
#include <ATen/cuda/CUDAContext.h>

__global__ void fused_linred_kernel(const float* __restrict__ x,
                                    const float* __restrict__ wsum,
                                    float bsum,
                                    float* __restrict__ y,
                                    int B, int K) {
  int row = blockIdx.x;
  if (row >= B) return;
  float acc = 0.f;
  for (int k = threadIdx.x; k < K; k += blockDim.x) {
    acc += x[row * K + k] * wsum[k];
  }
  __shared__ float sh[256];
  int tid = threadIdx.x;
  sh[tid] = acc;
  __syncthreads();
  for (int s = blockDim.x / 2; s > 0; s >>= 1) {
    if (tid < s) sh[tid] += sh[tid + s];
    __syncthreads();
  }
  if (tid == 0) y[row] = sh[0] + bsum;
}

torch::Tensor fused_linear_sum(torch::Tensor x, torch::Tensor w, torch::Tensor b) {
  TORCH_CHECK(x.is_cuda() && w.is_cuda() && b.is_cuda(), "All tensors must be CUDA");
  TORCH_CHECK(x.scalar_type() == at::kFloat && w.scalar_type() == at::kFloat && b.scalar_type() == at::kFloat, "float32 only");
  auto xc = x.contiguous(), wc = w.contiguous(), bc = b.contiguous();
  TORCH_CHECK(wc.size(1) == xc.size(1), "in_features mismatch");
  int64_t B = xc.size(0), K = xc.size(1);
  auto wsum = wc.sum(0);
  float bsum = bc.sum().item<float>();
  auto y = torch::empty({B, 1}, xc.options());
  int threads = 256;
  fused_linred_kernel<<<(int)B, threads, 0, at::cuda::getCurrentCUDAStream()>>>(
      xc.data_ptr<float>(), wsum.data_ptr<float>(), bsum, y.data_ptr<float>(), (int)B, (int)K);
  return y;
}
""",
      functions=["fused_linear_sum"],
      verbose=False
  )

