    cuda_src = r"""
    #include <torch/extension.h>
    #include <ATen/cuda/CUDAContext.h>
    #include <cuda_runtime.h>

    // Warp-level reduction for float using shuffle instructions
    __inline__ __device__ float warp_reduce_sum(float val) {
        unsigned mask = 0xffffffffu;
        for (int offset = 16; offset > 0; offset >>= 1) {
            val += __shfl_down_sync(mask, val, offset);
        }
        return val;
    }

    template <typename FnWriteOut>
    __inline__ __device__ void block_reduce_and_write(float thread_sum, int red_len, float* smem, FnWriteOut write_out) {
        int lane = threadIdx.x & 31;
        int warp_id = threadIdx.x >> 5;
        // Reduce within warp
        float val = warp_reduce_sum(thread_sum);

        // Write warp result to shared memory
        if (lane == 0) {
            smem[warp_id] = val;
        }
        __syncthreads();

        // Number of warps in the block
        int num_warps = (blockDim.x + 31) >> 5;

        // First warp reduces the warp results
        float block_sum = 0.0f;
        if (warp_id == 0) {
            block_sum = (lane < num_warps) ? smem[lane] : 0.0f;
            block_sum = warp_reduce_sum(block_sum);
            if (lane == 0) {
                // Write out mean (sum / red_len)
                write_out(block_sum / static_cast<float>(red_len));
            }
        }
    }

    // Kernel: reduce along dim=2 (last dimension)
    __global__ void reduce_mean_dim2_kernel(const float* __restrict__ x, float* __restrict__ out,
                                            int B, int D1, int D2) {
        int d1 = blockIdx.x;
        int b  = blockIdx.y;
        if (d1 >= D1 || b >= B) return;

        const float* row = x + ((b * D1 + d1) * D2);
        float thread_sum = 0.0f;

        // Vectorized path when aligned and divisible by 4
        bool can_vec4 = ((D2 & 3) == 0) && ((((uintptr_t)row) & 15) == 0);
        if (can_vec4) {
            const float4* __restrict__ row4 = reinterpret_cast<const float4*>(row);
            int D2_4 = D2 >> 2;
            for (int j4 = threadIdx.x; j4 < D2_4; j4 += blockDim.x) {
                float4 v = row4[j4];
                thread_sum += (v.x + v.y + v.z + v.w);
            }
        } else {
            for (int j = threadIdx.x; j < D2; j += blockDim.x) {
                thread_sum += row[j];
            }
        }

        extern __shared__ float smem[];
        auto write_out = [&] __device__ (float mean_val) {
            out[b * D1 + d1] = mean_val;
        };
        block_reduce_and_write(thread_sum, D2, smem, write_out);
    }

    // Kernel: reduce along dim=1 (middle dimension)
    __global__ void reduce_mean_dim1_kernel(const float* __restrict__ x, float* __restrict__ out,
                                            int B, int D1, int D2) {
        int d2 = blockIdx.x;
        int b  = blockIdx.y;
        if (d2 >= D2 || b >= B) return;

        float thread_sum = 0.0f;
        for (int d1 = threadIdx.x; d1 < D1; d1 += blockDim.x) {
            thread_sum += x[((b * D1 + d1) * D2) + d2];
        }

        extern __shared__ float smem[];
        auto write_out = [&] __device__ (float mean_val) {
            out[b * D2 + d2] = mean_val;
        };
        block_reduce_and_write(thread_sum, D1, smem, write_out);
    }

    // Kernel: reduce along dim=0 (first dimension)
    __global__ void reduce_mean_dim0_kernel(const float* __restrict__ x, float* __restrict__ out,
                                            int B, int D1, int D2) {
        int d1 = blockIdx.x;
        int d2 = blockIdx.y;
        if (d1 >= D1 || d2 >= D2) return;

        float thread_sum = 0.0f;
        for (int b = threadIdx.x; b < B; b += blockDim.x) {
            thread_sum += x[((b * D1 + d1) * D2) + d2];
        }

        extern __shared__ float smem[];
        auto write_out = [&] __device__ (float mean_val) {
            out[d1 * D2 + d2] = mean_val;
        };
        block_reduce_and_write(thread_sum, B, smem, write_out);
    }

    static inline int compute_block_size(int64_t red_len) {
        int block = 1;
        while (block < red_len && block < 1024) block <<= 1;
        if (block > 1024) block = 1024;
        if (block < 256) block = (int)std::min<int64_t>(red_len, 256);
        if (block < 128) block = 128; // final safeguard
        return block;
    }

    at::Tensor mean3d_dim_forward(at::Tensor x, int64_t dim) {
        TORCH_CHECK(x.is_cuda(), "mean3d_dim_forward: input must be a CUDA tensor");
        TORCH_CHECK(x.dtype() == at::kFloat, "mean3d_dim_forward: only float32 supported");
        TORCH_CHECK(x.dim() == 3, "mean3d_dim_forward: input must be 3D [B, D1, D2]");

        auto x_contig = x.contiguous();
        int64_t B = x_contig.size(0);
        int64_t D1 = x_contig.size(1);
        int64_t D2 = x_contig.size(2);

        if (dim < 0) dim += 3;
        TORCH_CHECK(dim >= 0 && dim < 3, "mean3d_dim_forward: dim must be in {0,1,2}");

        at::Tensor out;
        if (dim == 2) {
            out = at::empty({B, D1}, x_contig.options());
        } else if (dim == 1) {
            out = at::empty({B, D2}, x_contig.options());
        } else {
            out = at::empty({D1, D2}, x_contig.options());
        }

        const float* x_ptr = x_contig.data_ptr<float>();
        float* out_ptr = out.data_ptr<float>();

        cudaStream_t stream = at::cuda::getCurrentCUDAStream();

        if (dim == 2) {
            int block = compute_block_size(D2);
            int num_warps = (block + 31) >> 5;
            size_t shm = num_warps * sizeof(float);
            dim3 grid((unsigned int)D1, (unsigned int)B, 1u);
            reduce_mean_dim2_kernel<<<grid, block, shm, stream>>>(x_ptr, out_ptr, (int)B, (int)D1, (int)D2);
        } else if (dim == 1) {
            int block = compute_block_size(D1);
            int num_warps = (block + 31) >> 5;
            size_t shm = num_warps * sizeof(float);
            dim3 grid((unsigned int)D2, (unsigned int)B, 1u);
            reduce_mean_dim1_kernel<<<grid, block, shm, stream>>>(x_ptr, out_ptr, (int)B, (int)D1, (int)D2);
        } else { // dim == 0
            int block = compute_block_size(B);
            int num_warps = (block + 31) >> 5;
            size_t shm = num_warps * sizeof(float);
            dim3 grid((unsigned int)D1, (unsigned int)D2, 1u);
            reduce_mean_dim0_kernel<<<grid, block, shm, stream>>>(x_ptr, out_ptr, (int)B, (int)D1, (int)D2);
        }

        // Rely on PyTorch stream semantics; no explicit cudaDeviceSynchronize here.
        return out;
    }
    """

    kb_ext = load_inline(
        name="kb_ext",
        cpp_sources=[cpp_src],
        cuda_sources=[cuda_src],
        functions=["mean3d_dim_forward"],
        with_cuda=True,
        verbose=False,
        extra_cuda_cflags=["-O3"],
        extra_cflags=["-O3"],
    )
except Exception:
    kb_ext = None


class ModelNew(nn.Module):
    """
    Drop-in replacement for Model that accelerates the mean reduction along a specified dim
    using a CUDA extension when beneficial, otherwise falls back to PyTorch.
    """
    def __init__(self, dim: int):
        super(ModelNew, self).__init__()
        self.dim = dim

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        # Normalize dimension
        dim = self.dim
        if x.dim() > 0:
            dim = dim if dim >= 0 else dim + x.dim()

        # Heuristics and dtype/device guards
        use_ext = (
            kb_ext is not None and
            x.is_cuda and
            x.dtype == torch.float32 and
            x.dim() == 3 and
            0 <= dim <= 2
        )

        if use_ext:
            red_len = x.size(dim)
            total_elems = x.numel()
            # Avoid kernel launch overhead on small problems
            if red_len >= 512 and total_elems >= int(1e5):
                return kb_ext.mean3d_dim_forward(x, int(dim))

        # Fallback to PyTorch reference for all other cases
        return torch.mean(x, dim=self.dim)


# Reference Model for context (not used directly by the extension)
