// ----------------------------------------------
// Pointwise 1x1 "conv": GEMM + optional bias add
// ----------------------------------------------
torch::Tensor pointwise1x1_forward(
    torch::Tensor input, torch::Tensor weight, c10::optional<torch::Tensor> bias_opt
) {
    TORCH_CHECK(input.device().is_cuda() && weight.device().is_cuda(), "pointwise1x1_forward: tensors must be CUDA");
    TORCH_CHECK(input.scalar_type() == torch::kFloat32 && weight.scalar_type() == torch::kFloat32, "pointwise1x1_forward: only float32 supported");

    auto x = input.contiguous();
    auto w = weight.contiguous(); // [C_out, C_in]

    TORCH_CHECK(w.dim() == 2, "pointwise1x1_forward: weight must be [C_out, C_in]");
    int64_t C_out = w.size(0);
    int64_t C_in  = w.size(1);

    TORCH_CHECK(x.dim() >= 3, "pointwise1x1_forward: input must be NCH..., got dim=", x.dim());
    TORCH_CHECK(x.size(1) == C_in, "pointwise1x1_forward: input C_in mismatch with weight");

    // Flatten all dims except channel into S
    int64_t N = x.size(0);
    int64_t S = x.numel() / (N * C_in);
    auto x2d = x.view({N * S, C_in});          // [N*S, C_in]
    auto wT  = w.transpose(0, 1).contiguous(); // [C_in, C_out]
    auto y2d = at::matmul(x2d, wT);            // [N*S, C_out]
    auto y   = y2d.view({N, C_out}).reshape({N, C_out, S}); // [N, C_out, S]

    if (bias_opt.has_value() && bias_opt.value().defined()) {
        auto b = bias_opt.value().contiguous();
        TORCH_CHECK(b.device().is_cuda() && b.scalar_type() == torch::kFloat32, "pointwise1x1_forward: bias must be CUDA float32");
        TORCH_CHECK(b.numel() == C_out, "pointwise1x1_forward: bias size mismatch");
        // Broadcast add over N and spatial S
        y = y + b.view({1, C_out, 1});
    }
    // Reshape back to original spatial dims
    std::vector<int64_t> out_sizes;
    out_sizes.reserve(x.dim());
    out_sizes.push_back(N);
    out_sizes.push_back(C_out);
    for (int i = 2; i < x.dim(); ++i) out_sizes.push_back(x.size(i));
    return y.view(out_sizes);
}

