KB_DEVICE_INLINE int64_t div_floor_int64(int64_t a, int64_t b) {
    return a / b;
}

__global__ void conv3d_naive_kernel(
    const float* __restrict__ input,      // [N, C_in, D_in, H_in, W_in]
    const float* __restrict__ weight,     // [C_out, C_in_per_group, Kd, Kh, Kw]
    const float* __restrict__ bias,       // [C_out] or nullptr
    float* __restrict__ output,           // [N, C_out, D_out, H_out, W_out]
    int64_t N, int64_t C_in, int64_t D_in, int64_t H_in, int64_t W_in,
    int64_t C_out, int64_t Kd, int64_t Kh, int64_t Kw,
    int64_t D_out, int64_t H_out, int64_t W_out,
    int64_t stride_d, int64_t stride_h, int64_t stride_w,
    int64_t pad_d, int64_t pad_h, int64_t pad_w,
    int64_t dil_d, int64_t dil_h, int64_t dil_w,
    int64_t groups
) {
    int64_t total = N * C_out * D_out * H_out * W_out;
    int64_t idx = blockIdx.x * (int64_t)blockDim.x + threadIdx.x;
    if (idx >= total) return;

    // Decode linear index
    int64_t ow = idx % W_out;
    int64_t tmp = idx / W_out;
    int64_t oh = tmp % H_out;
    tmp = tmp / H_out;
    int64_t od = tmp % D_out;
    tmp = tmp / D_out;
    int64_t co = tmp % C_out;
    int64_t n  = tmp / C_out;

    int64_t c_out_per_group = C_out / groups;
    int64_t c_in_per_group  = C_in / groups;
    int64_t g = co / c_out_per_group;
    int64_t ci_base = g * c_in_per_group;

    float acc = 0.0f;

    // Iterate over input channels within the group and kernel window
    for (int64_t ci = 0; ci < c_in_per_group; ++ci) {
        int64_t c = ci_base + ci;
        for (int64_t kd = 0; kd < Kd; ++kd) {
            int64_t in_d = od * stride_d - pad_d + kd * dil_d;
            if ((unsigned long long)in_d >= (unsigned long long)D_in) continue;
            for (int64_t kh = 0; kh < Kh; ++kh) {
                int64_t in_h = oh * stride_h - pad_h + kh * dil_h;
                if ((unsigned long long)in_h >= (unsigned long long)H_in) continue;
                for (int64_t kw = 0; kw < Kw; ++kw) {
                    int64_t in_w = ow * stride_w - pad_w + kw * dil_w;
                    if ((unsigned long long)in_w >= (unsigned long long)W_in) continue;

                    // input offset: ((((n*C_in + c)*D_in + in_d)*H_in + in_h)*W_in + in_w)
                    int64_t in_off = (((n * C_in + c) * D_in + in_d) * H_in + in_h) * W_in + in_w;

                    // weight offset: ((((co)*c_in_per_group + ci)*Kd + kd)*Kh + kh)*Kw + kw
                    int64_t wt_off = ((((co) * c_in_per_group + ci) * Kd + kd) * Kh + kh) * Kw + kw;

                    acc += input[in_off] * weight[wt_off];
                }
            }
        }
    }

    if (bias != nullptr) {
        acc += bias[co];
    }

    // output offset: ((((n*C_out + co)*D_out + od)*H_out + oh)*W_out + ow)
    int64_t out_off = (((n * C_out + co) * D_out + od) * H_out + oh) * W_out + ow;
    output[out_off] = acc;
}

torch::Tensor conv3d_forward(
    torch::Tensor input, torch::Tensor weight, c10::optional<torch::Tensor> bias_opt,
    int64_t stride_d, int64_t stride_h, int64_t stride_w,
    int64_t pad_d, int64_t pad_h, int64_t pad_w,
    int64_t dil_d, int64_t dil_h, int64_t dil_w,
    int64_t groups
) {
    TORCH_CHECK(input.device().is_cuda() && weight.device().is_cuda(), "conv3d_forward: tensors must be on CUDA");
    TORCH_CHECK(input.scalar_type() == torch::kFloat32 && weight.scalar_type() == torch::kFloat32, "conv3d_forward: only float32 supported");
    TORCH_CHECK(input.dim() == 5, "conv3d_forward: input must be [N, C_in, D, H, W]");
    TORCH_CHECK(weight.dim() == 5, "conv3d_forward: weight must be [C_out, C_in/groups, Kd, Kh, Kw]");

    auto x = input.contiguous();
    auto w = weight.contiguous();

    int64_t N = x.size(0);
    int64_t C_in = x.size(1);
    int64_t D_in = x.size(2);
    int64_t H_in = x.size(3);
    int64_t W_in = x.size(4);

    int64_t C_out = w.size(0);
    int64_t Cin_div_g = w.size(1);
    int64_t Kd = w.size(2);
    int64_t Kh = w.size(3);
    int64_t Kw = w.size(4);

    TORCH_CHECK(groups > 0, "conv3d_forward: groups must be > 0");
    TORCH_CHECK(C_in % groups == 0, "conv3d_forward: C_in must be divisible by groups");
    TORCH_CHECK(Cin_div_g == C_in / groups, "conv3d_forward: weight C_in/groups mismatch with input and groups");
    TORCH_CHECK(C_out % groups == 0, "conv3d_forward: C_out must be divisible by groups");

    // Output dims
    int64_t D_out = (D_in + 2 * pad_d - dil_d * (Kd - 1) - 1) / stride_d + 1;
    int64_t H_out = (H_in + 2 * pad_h - dil_h * (Kh - 1) - 1) / stride_h + 1;
    int64_t W_out = (W_in + 2 * pad_w - dil_w * (Kw - 1) - 1) / stride_w + 1;

    TORCH_CHECK(D_out >= 0 && H_out >= 0 && W_out >= 0, "conv3d_forward: computed negative output size");

    c10::optional<at::Tensor> bias_c10 = c10::nullopt;
    const float* bias_ptr = nullptr;
    if (bias_opt.has_value() && bias_opt.value().defined()) {
        auto b = bias_opt.value().contiguous();
        TORCH_CHECK(b.device().is_cuda() && b.scalar_type() == torch::kFloat32, "conv3d_forward: bias must be CUDA float32");
        TORCH_CHECK(b.numel() == C_out, "conv3d_forward: bias must have numel == C_out");
        bias_c10 = b;
        bias_ptr = b.data_ptr<float>();
    }

    auto out = at::empty({N, C_out, D_out, H_out, W_out}, x.options());

    int64_t total = N * C_out * D_out * H_out * W_out;
    if (total == 0) {
        return out;
    }

    const float* x_ptr = x.data_ptr<float>();
    const float* w_ptr = w.data_ptr<float>();
    float* y_ptr = out.data_ptr<float>();

    cudaStream_t stream = at::cuda::getCurrentCUDAStream();
    const int threads = 256;
    const int64_t blocks64 = (total + threads - 1) / threads;
    const dim3 grid((unsigned int)std::min<int64_t>(blocks64, INT_MAX));
    const dim3 block(threads);

    conv3d_naive_kernel<<<grid, block, 0, stream>>>(
        x_ptr, w_ptr, bias_ptr, y_ptr,
        N, C_in, D_in, H_in, W_in,
        C_out, Kd, Kh, Kw,
        D_out, H_out, W_out,
        stride_d, stride_h, stride_w,
        pad_d, pad_h, pad_w,
        dil_d, dil_h, dil_w,
        groups
    );
    C10_CUDA_KERNEL_LAUNCH_CHECK();

    return out;
}
"""

_kb_ext = load_inline(
    name="kb_ext",
    cpp_sources=[_cpp_src],
    cuda_sources=[_cuda_src],
    functions=[
        "matmul_forward",
        "bmm_forward",
        "conv_transpose2d_forward",
        "conv_transpose3d_forward",
        "pointwise1x1_forward",
        "conv3d_forward",
    ],
    with_cuda=True,
    verbose=False,
    extra_cuda_cflags=["-O3"],
    extra_cflags=["-O3"],
)

class ModelNew(nn.Module):
    """
    Drop-in replacement for Model that mirrors its API and semantics exactly.
    Internally uses a custom CUDA extension to accelerate Conv3d forward when:
      - tensors are CUDA float32
      - problem size is large enough to amortize overhead
      - autograd is disabled (to preserve gradient semantics)
    Otherwise, it falls back to PyTorch's Conv3d (cuDNN) for full correctness.
    """
    def __init__(
        self,
        in_channels: int,
        out_channels: int,
        kernel_size: int,
        stride: int = 1,
        padding: int = 0,
        dilation: int = 1,
        groups: int = 1,
        bias: bool = False,
    ):
        super(ModelNew, self).__init__()
        # Mirror Model exactly: same submodule and parameter registrations
        self.conv3d = nn.Conv3d(
            in_channels,
            out_channels,
            (kernel_size, kernel_size, kernel_size),
            stride=stride,
            padding=padding,
            dilation=dilation,
            groups=groups,
            bias=bias,
        )

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        # Heuristic gating for the extension fast path
        w = self.conv3d.weight
        b = self.conv3d.bias

        # Require CUDA float32 tensors and no autograd (to preserve gradients in training)
        cond_types = (
            x.is_cuda
            and w.is_cuda
            and x.dtype == torch.float32
            and w.dtype == torch.float32
            and not torch.is_grad_enabled()
        )
        if not cond_types:
            return self.conv3d(x)

        # Extract conv params (tuples)
        sd, sh, sw = self.conv3d.stride
        pd, ph, pw = self.conv3d.padding
        dd, dh, dw = self.conv3d.dilation
        groups = self.conv3d.groups

        # Compute output sizes to make a size-based decision
        N, Cin, Din, Hin, Win = x.shape
        Kd, Kh, Kw = w.shape[2], w.shape[3], w.shape[4]

        Dout = (Din + 2 * pd - dd * (Kd - 1) - 1) // sd + 1
        Hout = (Hin + 2 * ph - dh * (Kh - 1) - 1) // sh + 1
        Wout = (Win + 2 * pw - dw * (Kw - 1) - 1) // sw + 1

        # Only attempt fast path when size is reasonably large
        # to amortize launch/dispatch overheads
        out_elems = N * self.conv3d.out_channels * max(0, Dout) * max(0, Hout) * max(0, Wout)

        # Threshold heuristic (tune as needed)
        use_ext = out_elems >= 100_000

        if not use_ext:
            return self.conv3d(x)

        # Route to the extension kernel
        bias_opt = b if b is not None else None

        return _kb_ext.conv3d_forward(
            x,
            w,
            bias_opt,
            int(sd),
            int(sh),
            int(sw),
            int(pd),
            int(ph),
            int(pw),
            int(dd),
            int(dh),
            int(dw),
            int(groups),
        )


# If this file is run directly, a quick smoke test can be performed
if __name__ == "__main__":
    torch.manual_seed(0)
    device = "cuda" if torch.cuda.is_available() else "cpu"

    # Small correctness check vs PyTorch reference
    N, Cin, Cout = 2, 3, 4
    D, H, W = 8, 9, 10
    K = 3
    stride = 2
    pad = 1
    dil = 1
    groups = 1
    bias = True

    x = torch.randn(N, Cin, D, H, W, device=device, dtype=torch.float32)
    ref = nn.Conv3d(Cin, Cout, (K, K, K), stride=stride, padding=pad, dilation=dil, groups=groups, bias=bias).to(device)
    model = ModelNew(Cin, Cout, K, stride=stride, padding=pad, dilation=dil, groups=groups, bias=bias).to(device)

    # Copy weights/bias so outputs match exactly
    with torch.no_grad():
        model.conv3d.weight.copy_(ref.weight)
        if bias:
            model.conv3d.bias.copy_(ref.bias)

    # Force fallback path (grad enabled)
    torch.set_grad_enabled(True)
    y_ref = ref(x)
    y_fb = model(x)
    torch.set_grad_enabled(False)

    # Fast path (no grad)
    y_fast = model(x)

    max_abs_diff_fb = (y_ref - y_fb).abs().max().item()
    max_abs_diff_fast = (y_ref - y_fast).abs().max().item()

    print("Fallback path max abs diff:", max_abs_diff_fb)
    print("Fast path max abs diff:", max_abs_diff_fast)
    print("Outputs identical within tolerance:", max_abs_diff_fast < 1e-4)

