import os
import math
import uuid
import torch
import torch.nn as nn
import torch.nn.functional as F
from torch.utils.cpp_extension import load_inline

_DW_PW_EXT = None
_DW_PW_EXT_BUILT = False
_DW_PW_EXT_ERR = None


def _build_dw_pw_extension():
    global _DW_PW_EXT, _DW_PW_EXT_BUILT, _DW_PW_EXT_ERR
    if _DW_PW_EXT_BUILT and _DW_PW_EXT is not None:
        return _DW_PW_EXT

    name = f"dw_pw_ext_{uuid.uuid4().hex[:8]}"

    cpp_sources = r"""
    #include <torch/extension.h>

    // Depthwise forward (supports bias via bias tensor; pass empty tensor if no bias)
    torch::Tensor depthwise_forward(torch::Tensor x,
                                    torch::Tensor weight,
                                    torch::Tensor bias,
                                    int64_t sH, int64_t sW,
                                    int64_t pH, int64_t pW,
                                    int64_t dH, int64_t dW);

    // Pointwise forward (1x1 conv), supports optional bias (pass empty tensor for none)
    torch::Tensor pointwise_forward(torch::Tensor x,
                                    torch::Tensor weight,
                                    torch::Tensor bias);
    """

    cuda_sources = r"""
    #include <torch/extension.h>
    #include <ATen/cuda/CUDAContext.h>
    #include <cuda_runtime.h>

    // Helpers
    static inline int64_t div_up_int64(int64_t a, int64_t b) {
        return (a + b - 1) / b;
    }

    // Depthwise kernel: one block per (tile in H_out x W_out) and per (n,c) in grid.z
    template <int TILE_H, int TILE_W>
    __global__ void depthwise_kernel(const float* __restrict__ x,
                                     const float* __restrict__ w,
                                     const float* __restrict__ b, bool has_bias,
                                     int64_t N, int64_t C,
                                     int64_t H, int64_t W,
                                     int64_t kH, int64_t kW,
                                     int64_t sH, int64_t sW,
                                     int64_t pH, int64_t pW,
                                     int64_t dH, int64_t dW,
                                     int64_t H_out, int64_t W_out,
                                     float* __restrict__ y) {
        int64_t nc = blockIdx.z; // encode (n, c)
        int64_t n = nc / C;
        int64_t c = nc % C;

        int oh = blockIdx.y * TILE_H + threadIdx.y;
        int ow = blockIdx.x * TILE_W + threadIdx.x;

        if (oh >= H_out || ow >= W_out) return;

        // Base pointers
        int64_t in_hw = H * W;
        int64_t out_hw = H_out * W_out;

        const float* x_ptr = x + ((n * C + c) * in_hw);
        const float* w_ptr = w + (c * kH * kW);
        float* y_ptr = y + ((n * C + c) * out_hw);

        float acc = 0.f;

        // Convolution sum over KxK for this (oh, ow)
        int64_t ih0 = oh * sH - pH;
        int64_t iw0 = ow * sW - pW;

        for (int kh = 0; kh < kH; ++kh) {
            int64_t ih = ih0 + kh * dH;
            if ((unsigned long long)ih >= (unsigned long long)H) continue;
            for (int kw = 0; kw < kW; ++kw) {
                int64_t iw = iw0 + kw * dW;
                if ((unsigned long long)iw >= (unsigned long long)W) continue;
                float xv = x_ptr[ih * W + iw];
                float ww = w_ptr[kh * kW + kw];
                acc = fmaf(xv, ww, acc);
            }
        }

        if (has_bias) {
            acc += b[c];
        }

        y_ptr[oh * W_out + ow] = acc;
    }

    // Pointwise 1x1 kernel: For each (n, oc, h, w), sum over ic
    template <int TILE_H, int TILE_W>
    __global__ void pointwise_kernel(const float* __restrict__ x,
                                     const float* __restrict__ w,
                                     const float* __restrict__ b, bool has_bias,
                                     int64_t N, int64_t C_in, int64_t C_out,
                                     int64_t H, int64_t W,
                                     float* __restrict__ y) {
        // Map grid.z to (n, oc)
        int64_t no = blockIdx.z;
        int64_t n = no / C_out;
        int64_t oc = no % C_out;

        int oh = blockIdx.y * TILE_H + threadIdx.y;
        int ow = blockIdx.x * TILE_W + threadIdx.x;
        if (oh >= H || ow >= W) return;

        int64_t in_hw = H * W;
        int64_t out_hw = H * W;

        // input [N, C_in, H, W]
        // weight [C_out, C_in]
        const float* w_row = w + oc * C_in;

        float acc = 0.f;
        // Accumulate over input channels
        for (int64_t ic = 0; ic < C_in; ++ic) {
            const float* x_ptr = x + ((n * C_in + ic) * in_hw);
            float xv = x_ptr[oh * W + ow];
            float ww = w_row[ic];
            acc = fmaf(xv, ww, acc);
        }
        if (has_bias) {
            acc += b[oc];
        }

        float* y_ptr = y + ((n * C_out + oc) * out_hw);
        y_ptr[oh * W + ow] = acc;
    }

    // Wrapper: depthwise_forward
    torch::Tensor depthwise_forward(torch::Tensor x,
                                    torch::Tensor weight,
                                    torch::Tensor bias,
                                    int64_t sH, int64_t sW,
                                    int64_t pH, int64_t pW,
                                    int64_t dH, int64_t dW) {
        TORCH_CHECK(x.is_cuda(), "x must be CUDA tensor");
        TORCH_CHECK(weight.is_cuda(), "weight must be CUDA tensor");
        TORCH_CHECK(x.dtype() == torch::kFloat32, "x must be float32");
        TORCH_CHECK(weight.dtype() == torch::kFloat32, "weight must be float32");
        TORCH_CHECK(x.dim() == 4, "x must be 4D NCHW");
        TORCH_CHECK(weight.dim() == 4, "weight must be 4D [C_out, 1, kH, kW]");
        TORCH_CHECK(x.is_contiguous(), "x must be contiguous");
        TORCH_CHECK(weight.is_contiguous(), "weight must be contiguous");

        auto N = x.size(0);
        auto C = x.size(1);
        auto H = x.size(2);
        auto W = x.size(3);

        TORCH_CHECK(weight.size(0) == C, "depthwise weight.size(0) must equal C");
        TORCH_CHECK(weight.size(1) == 1, "depthwise weight.size(1) must be 1");
        auto kH = weight.size(2);
        auto kW = weight.size(3);

        bool has_bias = false;
        const float* b_ptr = nullptr;
        if (bias.defined() && bias.numel() > 0) {
            TORCH_CHECK(bias.is_cuda(), "bias must be CUDA if provided");
            TORCH_CHECK(bias.dtype() == torch::kFloat32, "bias must be float32");
            TORCH_CHECK(bias.is_contiguous(), "bias must be contiguous");
            TORCH_CHECK(bias.dim() == 1 && bias.size(0) == C, "bias shape must be [C]");
            has_bias = true;
        }

        // Output dims (floor)
        int64_t H_out = (H + 2 * pH - dH * (kH - 1) - 1) / sH + 1;
        int64_t W_out = (W + 2 * pW - dW * (kW - 1) - 1) / sW + 1;
        TORCH_CHECK(H_out >= 0 && W_out >= 0, "Invalid output size computed");

        auto y = torch::empty({N, C, H_out, W_out}, x.options());

        const float* x_ptr = x.data_ptr<float>();
        const float* w_ptr = weight.data_ptr<float>();
        const float* bias_ptr = has_bias ? bias.data_ptr<float>() : nullptr;
        float* y_ptr = y.data_ptr<float>();

        dim3 block(16, 16, 1);
        dim3 grid(div_up_int64(W_out, block.x), div_up_int64(H_out, block.y), N * C);

        auto stream = at::cuda::getCurrentCUDAStream();

        depthwise_kernel<16,16><<<grid, block, 0, stream>>>(
            x_ptr, w_ptr, bias_ptr, has_bias, N, C, H, W, kH, kW, sH, sW, pH, pW, dH, dW, H_out, W_out, y_ptr
        );
        C10_CUDA_KERNEL_LAUNCH_CHECK();

        return y;
    }

    // Wrapper: pointwise_forward (1x1)
    torch::Tensor pointwise_forward(torch::Tensor x,
                                    torch::Tensor weight,
                                    torch::Tensor bias) {
        TORCH_CHECK(x.is_cuda(), "x must be CUDA tensor");
        TORCH_CHECK(weight.is_cuda(), "weight must be CUDA tensor");
        TORCH_CHECK(x.dtype() == torch::kFloat32, "x must be float32");
        TORCH_CHECK(weight.dtype() == torch::kFloat32, "weight must be float32");
        TORCH_CHECK(x.dim() == 4, "x must be 4D NCHW");
        TORCH_CHECK(weight.dim() == 4, "weight must be 4D [C_out, C_in, 1, 1]");
        TORCH_CHECK(x.is_contiguous(), "x must be contiguous");
        TORCH_CHECK(weight.is_contiguous(), "weight must be contiguous");

        auto N = x.size(0);
        auto C_in = x.size(1);
        auto H = x.size(2);
        auto W = x.size(3);

        TORCH_CHECK(weight.size(2) == 1 && weight.size(3) == 1, "pointwise weight must be 1x1");
        auto C_out = weight.size(0);
        TORCH_CHECK(weight.size(1) == C_in, "pointwise weight size(1) must equal input channels");

        bool has_bias = false;
        const float* b_ptr = nullptr;
        if (bias.defined() && bias.numel() > 0) {
            TORCH_CHECK(bias.is_cuda(), "bias must be CUDA if provided");
            TORCH_CHECK(bias.dtype() == torch::kFloat32, "bias must be float32");
            TORCH_CHECK(bias.is_contiguous(), "bias must be contiguous");
            TORCH_CHECK(bias.dim() == 1 && bias.size(0) == C_out, "bias shape must be [C_out]");
            has_bias = true;
        }

        auto y = torch::empty({N, C_out, H, W}, x.options());

        const float* x_ptr = x.data_ptr<float>();
        // Flatten weight to [C_out, C_in]
        auto w2 = weight.view({C_out, C_in}).contiguous();
        const float* w_ptr = w2.data_ptr<float>();
        const float* bias_ptr = has_bias ? bias.data_ptr<float>() : nullptr;
        float* y_ptr = y.data_ptr<float>();

        dim3 block(16, 16, 1);
        dim3 grid(div_up_int64(W, block.x), div_up_int64(H, block.y), N * C_out);

        auto stream = at::cuda::getCurrentCUDAStream();

        pointwise_kernel<16,16><<<grid, block, 0, stream>>>(
            x_ptr, w_ptr, bias_ptr, has_bias, N, C_in, C_out, H, W, y_ptr
        );
        C10_CUDA_KERNEL_LAUNCH_CHECK();

        return y;
    }
    """

    try:
        _DW_PW_EXT = load_inline(
            name=name,
            cpp_sources=[cpp_sources],
            cuda_sources=[cuda_sources],
            functions=["depthwise_forward", "pointwise_forward"],
            extra_cflags=["-O3"],
            extra_cuda_cflags=["-O3", "-use_fast_math"],
            verbose=True,
        )
        _DW_PW_EXT_BUILT = True
        return _DW_PW_EXT
    except Exception as e:
        _DW_PW_EXT_ERR = e
        _DW_PW_EXT = None
        _DW_PW_EXT_BUILT = True
        return None


class ModelNew(nn.Module):
    """
    Drop-in replacement for Model that accelerates the depthwise + pointwise
    forward pass with custom CUDA kernels when possible. Falls back to PyTorch
    Conv2d ops when training, on CPU, non-fp32, non-contiguous inputs, or if
    extension build fails.

    Args:
        in_channels (int): Number of channels in the input tensor.
        out_channels (int): Number of channels produced by the convolution.
        kernel_size (int): Size of the convolution kernel.
        stride (int, optional): Stride of the convolution. Defaults to 1.
        padding (int, optional): Padding applied to the input. Defaults to 0.
        dilation (int, optional): Spacing between kernel elements. Defaults to 1.
        bias (bool, optional): If `True`, adds a learnable bias to the output. Defaults to `False`.
    """
    def __init__(self, in_channels: int, out_channels: int, kernel_size: int, stride: int = 1, padding: int = 0, dilation: int = 1, bias: bool = False):
        super(ModelNew, self).__init__()
        # Mirror original submodules so state_dict is compatible
        self.depthwise = nn.Conv2d(in_channels, in_channels, kernel_size, stride=stride, padding=padding, dilation=dilation, groups=in_channels, bias=bias)
        self.pointwise = nn.Conv2d(in_channels, out_channels, kernel_size=1, bias=bias)

        # Try to build the extension once
        self.use_ext = False
        self._ext = None
        self._ext_build_err = None
        ext = _build_dw_pw_extension()
        if ext is not None:
            self._ext = ext
            self.use_ext = True
        else:
            self._ext_build_err = _DW_PW_EXT_ERR
            self.use_ext = False

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        """
        Performs the depthwise-separable 2D convolution.

        Args:
            x (torch.Tensor): Input tensor of shape (batch_size, in_channels, height, width).

        Returns:
            torch.Tensor: Output tensor of shape (batch_size, out_channels, height_out, width_out).
        """
        can_use = (
            self.use_ext and
            x.is_cuda and
            x.dtype == torch.float32 and
            (self.depthwise.weight.dtype == torch.float32) and
            (self.pointwise.weight.dtype == torch.float32) and
            not self.training and
            not x.requires_grad and
            not (self.depthwise.weight.requires_grad or (self.depthwise.bias is not None and self.depthwise.bias.requires_grad) or
                 self.pointwise.weight.requires_grad or (self.pointwise.bias is not None and self.pointwise.bias.requires_grad))
        )

        if can_use:
            # Ensure contiguity for kernels
            x_in = x.contiguous()
            dw_w = self.depthwise.weight.contiguous()
            pw_w = self.pointwise.weight.contiguous()

            # Depthwise bias (optional)
            if self.depthwise.bias is not None:
                dw_b = self.depthwise.bias.contiguous()
            else:
                dw_b = torch.empty(0, device=x.device, dtype=x.dtype)

            # Pointwise bias (optional)
            if self.pointwise.bias is not None:
                pw_b = self.pointwise.bias.contiguous()
            else:
                pw_b = torch.empty(0, device=x.device, dtype=x.dtype)

            sH = self.depthwise.stride[0]
            sW = self.depthwise.stride[1]
            pH = self.depthwise.padding[0]
            pW = self.depthwise.padding[1]
            dH = self.depthwise.dilation[0]
            dW = self.depthwise.dilation[1]

            # Run custom kernels
            y_dw = self._ext.depthwise_forward(x_in, dw_w, dw_b, sH, sW, pH, pW, dH, dW)
            # pointwise is 1x1 with stride=1, padding=0, dilation=1 implicitly
            y = self._ext.pointwise_forward(y_dw.contiguous(), pw_w, pw_b)
            return y
        else:
            # Fallback to PyTorch reference ops
            x = self.depthwise(x)
            x = self.pointwise(x)
            return x


# Original Model (kept for reference/testing compatibility)
class Model(nn.Module):
    """
    Performs a depthwise-separable 2D convolution operation.

    Args:
        in_channels (int): Number of channels in the input tensor.
        out_channels (int): Number of channels produced by the convolution.
        kernel_size (int): Size of the convolution kernel.
        stride (int, optional): Stride of the convolution. Defaults to 1.
        padding (int, optional): Padding applied to the input. Defaults to 0.
        dilation (int, optional): Spacing between kernel elements. Defaults to 1.
        bias (bool, optional): If `True`, adds a learnable bias to the output. Defaults to `False`.
    """
    def __init__(self, in_channels: int, out_channels: int, kernel_size: int, stride: int = 1, padding: int = 0, dilation: int = 1, bias: bool = False):
        super(Model, self).__init__()
        self.depthwise = nn.Conv2d(in_channels, in_channels, kernel_size, stride=stride, padding=padding, dilation=dilation, groups=in_channels, bias=bias)
        self.pointwise = nn.Conv2d(in_channels, out_channels, kernel_size=1, bias=bias)

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        """
        Performs the depthwise-separable 2D convolution.

        Args:
            x (torch.Tensor): Input tensor of shape (batch_size, in_channels, height, width).

        Returns:
            torch.Tensor: Output tensor of shape (batch_size, out_channels, height_out, width_out).
        """
        x = self.depthwise(x)
        x = self.pointwise(x)
        return x


