def _test_numerical_parity():
    torch.manual_seed(0)
    device = "cuda" if torch.cuda.is_available() else "cpu"
    batch_size = 2
    in_channels = 8
    out_channels = 16
    kernel_size = 3
    width = 32
    height = 32
    stride = 1
    padding = 1
    dilation = 1
    bias = True

    m_ref = Model(in_channels, out_channels, kernel_size, stride, padding, dilation, bias=bias).to(device).eval()
    m_new = ModelNew(in_channels, out_channels, kernel_size, stride, padding, dilation, bias=bias).to(device).eval()
    # copy weights
    m_new.load_state_dict(m_ref.state_dict())

    x = torch.randn(batch_size, in_channels, height, width, device=device, dtype=torch.float32)
    with torch.no_grad():
        y_ref = m_ref(x)
        y_new = m_new(x)
    max_abs = (y_ref - y_new).abs().max().item()
    print("Max abs diff:", max_abs)
