import math
from typing import Tuple, List, Optional

import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

kb_ext = None

_cpp_decl = r"""
#include <torch/extension.h>

// fused conv_transpose2d + post-processing (extra bias + clamp + scale + clamp + divide)
// Arguments:
//  - input: N x C_in x H x W (float32, CUDA, contiguous)
//  - weight: C_in x (C_out/groups) x kH x kW (float32, CUDA, contiguous)
//  - conv_bias: optional, shape (C_out) (float32, CUDA)
//  - extra_bias: (C_out, 1, 1) or (C_out) (float32, CUDA)
//  - stride, padding, output_padding: vector<int64_t> of size 2
//  - groups: int64_t
//  - scale: double (will be cast to float)
//
// Returns:
//  - output: N x C_out x H_out x W_out (float32, CUDA)
torch::Tensor fused_convtrans_post(
    torch::Tensor input,
    torch::Tensor weight,
    c10::optional<torch::Tensor> conv_bias,
    torch::Tensor extra_bias,
    std::vector<int64_t> stride,
    std::vector<int64_t> padding,
    std::vector<int64_t> output_padding,
    int64_t groups,
    double scale
);
"""

_cuda_impl = r"""
#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>
#include <cuda_runtime.h>

namespace {

__device__ __forceinline__ float clamp01(float x) {
    // clamp to [0, 1]
    return fminf(fmaxf(x, 0.0f), 1.0f);
}

__global__ void fused_post_kernel(
    const float* __restrict__ in,
    float* __restrict__ out,
    const float* __restrict__ bias, // size C
    int N, int C, int H, int W,
    float scale)
{
    int c = blockIdx.x; // [0, C)
    int n = blockIdx.y; // [0, N)
    if (c >= C || n >= N) return;

    int HW = H * W;
    size_t base = ((size_t)n * (size_t)C + (size_t)c) * (size_t)HW;
    float b = bias[c];

    for (int idx = threadIdx.x; idx < HW; idx += blockDim.x) {
        size_t off = base + (size_t)idx;
        float v = in[off];
        // v = (v + b) |> clamp01 |> (*scale) |> clamp01 |> (/scale)
        v = v + b;
        v = clamp01(v);
        v = v * scale;
        v = clamp01(v);
        v = v / scale;
        out[off] = v;
    }
}

} // namespace

torch::Tensor fused_convtrans_post(
    torch::Tensor input,
    torch::Tensor weight,
    c10::optional<torch::Tensor> conv_bias,
    torch::Tensor extra_bias,
    std::vector<int64_t> stride,
    std::vector<int64_t> padding,
    std::vector<int64_t> output_padding,
    int64_t groups,
    double scale_double)
{
    TORCH_CHECK(input.is_cuda(), "input must be CUDA");
    TORCH_CHECK(weight.is_cuda(), "weight must be CUDA");
    TORCH_CHECK(input.scalar_type() == at::kFloat, "input must be float32");
    TORCH_CHECK(weight.scalar_type() == at::kFloat, "weight must be float32");
    TORCH_CHECK(input.dim() == 4, "input must be 4D NCHW");
    TORCH_CHECK(weight.dim() == 4, "weight must be 4D (C_in, C_out/groups, kH, kW)");
    TORCH_CHECK(stride.size() == 2 && padding.size() == 2 && output_padding.size() == 2, "stride/padding/output_padding must have 2 elements");
    TORCH_CHECK(groups >= 1, "groups must be >= 1");

    auto input_c = input.contiguous();
    auto weight_c = weight.contiguous();

