        else:
            self._sH, self._sW = stride

        if isinstance(padding, int):
            self._pH = self._pW = padding
        else:
            self._pH, self._pW = padding

        if isinstance(output_padding, int):
            self._opH = self._opW = output_padding
        else:
            self._opH, self._opW = output_padding

    def _should_use_ext(self, x: torch.Tensor) -> bool:
        # Only float32 on CUDA
        if kb_ext is None:
            return False
        if not x.is_cuda:
            return False
        if x.dtype != torch.float32:
            return False
        if self.conv_transpose.weight.dtype != torch.float32:
            return False
        if self.bias.dtype != torch.float32:
            return False
        if self.conv_transpose.groups != 1:
            # Only standard grouped==1 supported here
            return False

        # Heuristics to avoid overhead on tiny problems
        N, Cin, Hin, Win = x.shape
        # Estimate output spatial size for ConvTranspose2d
        Hout = (Hin - 1) * self._sH - 2 * self._pH + (self._kH - 1) + self._opH + 1
        Wout = (Win - 1) * self._sW - 2 * self._pW + (self._kW - 1) + self._opW + 1
        Cout = self.conv_transpose.out_channels

        # Thresholds
        if N < 4:
            return False
        if Hout < 8 or Wout < 8 or Cin < 4 or Cout < 16:
            return False
        total_elems = N * Cout * Hout * Wout
        if total_elems < 1_000_000:
            # For small outputs, overhead might dominate
            return False

        return True

