        # Fast path: extension + fused post
        if self._should_use_ext(x):
            stride = [self._sH, self._sW]
            padding = [self._pH, self._pW]
            output_padding = [self._opH, self._opW]
            conv_bias = self.conv_transpose.bias
            # extra_bias expected as (C,1,1)
            extra_bias = self.bias
            out = kb_ext.fused_convtrans_post(
                x,
                self.conv_transpose.weight,
                conv_bias,
                extra_bias,
                stride,
                padding,
                output_padding,
                int(self.conv_transpose.groups),
                float(self.scaling_factor),
