        # Fallback: reference PyTorch behavior
        y = self.conv_transpose(x)
        y = y + self.bias
        y = torch.clamp(y, min=0.0, max=1.0)
        y = y * self.scaling_factor
        y = torch.clamp(y, min=0.0, max=1.0)
        y = y / self.scaling_factor
        return y


