import math
from typing import Any, List, Tuple

import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

# Build the CUDA extension once at import time
kb_ext = None
_cuda_cpp = r"""
#include <torch/extension.h>

// Forward declaration only (definitions in CUDA source)
torch::Tensor fused_bias_sum(torch::Tensor input, torch::Tensor bias);
"""

_cuda_src = r"""
#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>
#include <cuda_runtime.h>

static inline int next_pow2_ceil(int x) {
    int p = 1;
    while (p < x && p < 1024) p <<= 1;
    if (p < 32) p = 32; // ensure at least one warp
    return p;
}

__inline__ __device__ float warp_reduce_sum(float val) {
    unsigned mask = 0xffffffffu;
    // Warp-level reduction using shfl-down
    for (int offset = 16; offset > 0; offset >>= 1) {
        val += __shfl_down_sync(mask, val, offset);
    }
    return val;
}

// Kernel: each block reduces over C for a single batch n, fusing bias add.
__global__ void fused_bias_sum_kernel(const float* __restrict__ input,
                                      const float* __restrict__ bias,
                                      float* __restrict__ output,
                                      int C) {
    int n = blockIdx.x; // batch index
    int tid = threadIdx.x;
    int lane = tid & 31;
    int warp_id = tid >> 5;
    int num_warps = (blockDim.x + 31) >> 5;

    extern __shared__ float shmem[]; // one float per warp

    const float* row = input + (size_t)n * C;

    float local = 0.0f;

    // Vectorized path if C divisible by 4 (alignment is preserved when C % 4 == 0)
    if ((C & 3) == 0) {
        const int vecC = C >> 2; // C/4
        const float4* __restrict__ in4 = reinterpret_cast<const float4*>(row);
        const float4* __restrict__ b4  = reinterpret_cast<const float4*>(bias);
        for (int i = tid; i < vecC; i += blockDim.x) {
            float4 vi = in4[i];
            float4 vb = b4[i];
            local += (vi.x + vb.x) + (vi.y + vb.y) + (vi.z + vb.z) + (vi.w + vb.w);
        }
    } else {
        for (int c = tid; c < C; c += blockDim.x) {
            local += row[c] + bias[c];
        }
    }

    // Reduce within warp
    local = warp_reduce_sum(local);

    // Write warp results to shared memory
    if (lane == 0) {
        shmem[warp_id] = local;
    }
    __syncthreads();

    // Final reduction among warps by warp 0
    if (warp_id == 0) {
        float sum = (lane < num_warps) ? shmem[lane] : 0.0f;
        sum = warp_reduce_sum(sum);
        if (lane == 0) {
            output[n] = sum;
        }
    }
}

torch::Tensor fused_bias_sum(torch::Tensor input, torch::Tensor bias) {
    TORCH_CHECK(input.is_cuda(), "input must be a CUDA tensor");
    TORCH_CHECK(input.scalar_type() == at::kFloat, "input must be float32");
    TORCH_CHECK(input.dim() == 5, "input must be 5D (N, C, 1, 1, 1)");
    TORCH_CHECK(input.size(2) == 1 && input.size(3) == 1 && input.size(4) == 1,
                "spatial dims must be 1 after global average pooling");

    TORCH_CHECK(bias.is_cuda(), "bias must be a CUDA tensor");
    TORCH_CHECK(bias.scalar_type() == at::kFloat, "bias must be float32");
    TORCH_CHECK(bias.dim() == 1 || bias.dim() == 4,
                "bias must be 1D (C,) or 4D (C,1,1,1)");

    auto inp = input.contiguous();
    const int64_t N = inp.size(0);
    const int64_t C = inp.size(1);

    // Flatten input to (N, C)
    auto flat = inp.view({N, C});

    torch::Tensor bias_flat;
    if (bias.dim() == 4) {
        TORCH_CHECK(bias.size(1) == 1 && bias.size(2) == 1 && bias.size(3) == 1,
                    "bias 4D must be (C,1,1,1)");
        TORCH_CHECK(bias.size(0) == C, "bias channel mismatch");
        bias_flat = bias.contiguous().view({C});
    } else {
        TORCH_CHECK(bias.size(0) == C, "bias channel mismatch");
        bias_flat = bias.contiguous();
    }

    auto out = torch::empty({N}, inp.options());

    if (N == 0) {
        return out;
    }

    const float* input_ptr = flat.data_ptr<float>();
    const float* bias_ptr  = bias_flat.data_ptr<float>();
    float* out_ptr         = out.data_ptr<float>();

    int threads = next_pow2_ceil(static_cast<int>(C));
    dim3 block(threads);
    dim3 grid(static_cast<unsigned int>(N));
    size_t shmem_bytes = ((threads + 31) / 32) * sizeof(float);

    cudaStream_t stream = at::cuda::getCurrentCUDAStream();
    fused_bias_sum_kernel<<<grid, block, shmem_bytes, stream>>>(
        input_ptr, bias_ptr, out_ptr, static_cast<int>(C));

    return out;
}
"""

try:
    kb_ext = load_inline(
        name="kb_ext",
        cpp_sources=[_cuda_cpp],
        cuda_sources=[_cuda_src],
        functions=["fused_bias_sum"],
        with_cuda=True,
        extra_cflags=["-O3"],
        extra_cuda_cflags=["-O3"],
        verbose=False,
    )
except Exception:
    kb_ext = None


class ModelNew(nn.Module):
    """
    Drop-in replacement for Model that accelerates the final bias-add + sum reduction
    using a CUDA extension when possible. All other ops use PyTorch/cuDNN.
    """
    def __init__(self, in_channels, out_channels, kernel_size, divisor, pool_size, bias_shape, sum_dim):
        super(ModelNew, self).__init__()
        self.conv = nn.Conv3d(in_channels, out_channels, kernel_size)
        self.divisor = divisor
        self.max_pool = nn.MaxPool3d(pool_size)
        self.global_avg_pool = nn.AdaptiveAvgPool3d((1, 1, 1))
        self.bias = nn.Parameter(torch.randn(bias_shape))
        self.sum_dim = sum_dim

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        # Keep heavy ops on cuDNN/cuBLAS-backed PyTorch
        x = self.conv(x)
        x = x / self.divisor
        x = self.max_pool(x)
        x = self.global_avg_pool(x)  # (N, C, 1, 1, 1)

        # Use fused CUDA path when available and applicable
        use_fused = (
            kb_ext is not None
            and x.is_cuda
            and x.dtype == torch.float32
            and isinstance(self.sum_dim, int)
            and self.sum_dim == 1  # kernel reduces along channel dimension
            and x.dim() == 5
            and x.size(2) == 1 and x.size(3) == 1 and x.size(4) == 1
        )

        if use_fused:
            N, C = x.size(0), x.size(1)
            out_1d = kb_ext.fused_bias_sum(x.contiguous(), self.bias.contiguous())
            return out_1d.view(N, 1, 1, 1)

        # Fallback to PyTorch for correctness or non-CUDA
        x = x + self.bias
        x = torch.sum(x, dim=self.sum_dim)
        return x

