import os
import textwrap
import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

# Module-level cache for the compiled extension
_EXT_HANDLE = None
_EXT_BUILD_ATTEMPTED = False

def _build_mean_extension():
    global _EXT_HANDLE, _EXT_BUILD_ATTEMPTED
    if _EXT_BUILD_ATTEMPTED:
        return _EXT_HANDLE
    _EXT_BUILD_ATTEMPTED = True

    cpp_sources = r"""
    #include <torch/extension.h>
    // Declaration only; implementation is in the CUDA source.
    torch::Tensor mean_across_non_batch(torch::Tensor input);
    """

    cuda_sources = r"""
    #include <torch/extension.h>
    #include <ATen/cuda/CUDAContext.h>
    #include <cuda_runtime.h>

    template <typename index_t>
    __global__ void mean_reduce_kernel(const float* __restrict__ in,
                                       float* __restrict__ out,
                                       index_t N, index_t C, index_t D, index_t H, index_t W) {
        index_t n = blockIdx.x;
        if (n >= N) return;
        index_t inner = C * D * H * W;
        index_t base = n * inner;

        float thread_sum = 0.0f;
        for (index_t i = threadIdx.x; i < inner; i += blockDim.x) {
            thread_sum += in[base + i];
        }

        extern __shared__ float smem[];
        smem[threadIdx.x] = thread_sum;
        __syncthreads();

        // Block reduction
        for (unsigned int s = blockDim.x >> 1; s > 0; s >>= 1) {
            if (threadIdx.x < s) {
                smem[threadIdx.x] += smem[threadIdx.x + s];
            }
            __syncthreads();
        }

        if (threadIdx.x == 0) {
            out[n] = smem[0] / static_cast<float>(inner);
        }
    }

    torch::Tensor mean_across_non_batch(torch::Tensor input) {
        TORCH_CHECK(input.is_cuda(), "mean_across_non_batch: input must be a CUDA tensor");
        TORCH_CHECK(input.scalar_type() == at::kFloat, "mean_across_non_batch: only float32 is supported");
        TORCH_CHECK(input.dim() == 5, "mean_across_non_batch: expected 5D tensor [N, C, D, H, W]");
        TORCH_CHECK(input.is_contiguous(), "mean_across_non_batch: input must be contiguous");

        auto N = input.size(0);
        auto C = input.size(1);
        auto D = input.size(2);
        auto H = input.size(3);
        auto W = input.size(4);

        auto options = input.options();
        auto out = torch::empty({N}, options);

        const float* in_ptr = input.data_ptr<float>();
        float* out_ptr = out.data_ptr<float>();

        int threads = 256;
        dim3 blocks(N);
        size_t shmem = threads * sizeof(float);

        auto stream = at::cuda::getCurrentCUDAStream();
        mean_reduce_kernel<long long><<<blocks, threads, shmem, stream.stream()>>>(
            in_ptr, out_ptr,
            static_cast<long long>(N),
            static_cast<long long>(C),
            static_cast<long long>(D),
            static_cast<long long>(H),
            static_cast<long long>(W)
        );
        C10_CUDA_KERNEL_LAUNCH_CHECK();
        return out;
    }
    """

    try:
        _EXT_HANDLE = load_inline(
            name="mean_reduce_ext",
            cpp_sources=[cpp_sources],
            cuda_sources=[cuda_sources],
            functions=["mean_across_non_batch"],
            extra_cflags=["-O3"],
            extra_cuda_cflags=["-O3", "-use_fast_math"],
            verbose=True,
        )
    except Exception as e:
        # Failed to build; leave handle as None to trigger fallback
        _EXT_HANDLE = None
    return _EXT_HANDLE


class ModelNew(nn.Module):
    """
    Model that performs a 3D convolution, applies Group Normalization, computes the mean
    """
    def __init__(self, in_channels, out_channels, kernel_size, num_groups):
        super(ModelNew, self).__init__()
        self.conv = nn.Conv3d(in_channels, out_channels, kernel_size)
        self.group_norm = nn.GroupNorm(num_groups, out_channels)

        self.use_ext = False
        self._ext = _build_mean_extension()
        if self._ext is not None:
            self.use_ext = True

    def forward(self, x):
        """
        Args:
            x (torch.Tensor): Input tensor of shape (batch_size, in_channels, D, H, W).
        Returns:
            torch.Tensor: Output tensor of shape (batch_size,)
        """
        x = self.conv(x)
        x = self.group_norm(x)

        can_use_ext = (
            self.use_ext
            and x.is_cuda
            and x.dtype == torch.float32
            and not torch.is_grad_enabled()  # ensure we don't break autograd
        )

        if can_use_ext:
            x_contig = x.contiguous()
            out = self._ext.mean_across_non_batch(x_contig)
            return out
        else:
            # Fallback to PyTorch for correctness and autograd support
            return x.mean(dim=[1, 2, 3, 4])


# For compatibility with the original API
Model = ModelNew

def get_inputs():
    # Mirror helper from reference for convenience
