        x = self.instance_norm(x.unsqueeze(1).unsqueeze(1)).squeeze(1).squeeze(1)

        # The rest are simple elementwise ops. Use autograd-friendly fused path when on CUDA float32 with matching shapes.
        x = _FusedAddMulFn.apply(x, y)

        return x


