        if hasattr(base.instance_norm, "weight") and base.instance_norm.weight is not None:
            ref.instance_norm.weight.copy_(base.instance_norm.weight)
        if hasattr(base.instance_norm, "bias") and base.instance_norm.bias is not None:
            ref.instance_norm.bias.copy_(base.instance_norm.bias)

