    x.grad.zero_(); y.grad.zero_()
    out_new.backward(g)
    gx_new, gy_new = x.grad, y.grad
    print("Grad x max abs diff:", (gx_ref - gx_new).abs().max().item())
    print("Grad y max abs diff:", (gy_ref - gy_new).abs().max().item())

