import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline
from typing import Any, List, Tuple

# Build the CUDA extension once at import time
kb_ext = load_inline(
    name="kb_ext",
    cpp_sources=r"""
#include <torch/extension.h>

// Forward declaration of the function we expose to Python.
torch::Tensor lse_channel_reduce(torch::Tensor x, bool keepdim);
""",
    cuda_sources=r"""
#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>
#include <cuda_runtime.h>

// Kernel: compute logsumexp over channel dimension (dim=1) for NCDHW input.
// We map one thread to each (n, d, h, w) position and reduce over C in-register.
// This yields coalesced reads across threads for each channel iteration.
__global__ void lse_channel_kernel(
    const float* __restrict__ x,
    float* __restrict__ out,
    int N, int C, int D, int H, int W,
    int keepdim // kept for signature symmetry; same indexing for both shapes
) {
    int S = D * H * W;      // spatial size
    int P = N * S;          // positions per channel reduction
    int tid = blockIdx.x * blockDim.x + threadIdx.x;
    if (tid >= P) return;

    int n = tid / S;
    int s = tid - n * S;

    // Base pointer to first channel for this (n, s) position
    const float* base = x + (n * C * S) + s;

    // One-pass numerically stable log-sum-exp over channels
    float m = -INFINITY;
    float ssum = 0.0f;

    for (int c = 0; c < C; ++c) {
        float v = base[c * S];
        if (v <= m) {
            ssum += expf(v - m);
        } else {
            ssum = ssum * expf(m - v) + 1.0f;
            m = v;
        }
    }

    float res = logf(ssum) + m;

    // For both keepdim=True and False, the flattened indexing for output is identical:
    // keepdim=True -> (N,1,D,H,W) has N*S elements; keepdim=False -> (N,D,H,W) also N*S.
    out[tid] = res;
}

torch::Tensor lse_channel_reduce(torch::Tensor x, bool keepdim) {
    TORCH_CHECK(x.is_cuda(), "lse_channel_reduce: input must be a CUDA tensor");
    TORCH_CHECK(x.scalar_type() == at::kFloat, "lse_channel_reduce: only float32 is supported");
    TORCH_CHECK(x.dim() == 5, "lse_channel_reduce: expected input of shape (N, C, D, H, W)");
    x = x.contiguous();

    const int64_t N64 = x.size(0);
    const int64_t C64 = x.size(1);
    const int64_t D64 = x.size(2);
    const int64_t H64 = x.size(3);
    const int64_t W64 = x.size(4);

    TORCH_CHECK(C64 > 0, "lse_channel_reduce: channel dimension must be > 0");

    // Allocate output with proper shape and options
    at::Tensor out;
    if (keepdim) {
        out = at::empty({N64, 1, D64, H64, W64}, x.options());
    } else {
        out = at::empty({N64, D64, H64, W64}, x.options());
    }

    // Compute launch configuration
    const int64_t S64 = D64 * H64 * W64;
    const int64_t P64 = N64 * S64;

    const int threads = 256;
    const int blocks = static_cast<int>((P64 + threads - 1) / threads);

    cudaStream_t stream = at::cuda::getCurrentCUDAStream();

    lse_channel_kernel<<<blocks, threads, 0, stream>>>(
        x.data_ptr<float>(),
        out.data_ptr<float>(),
        static_cast<int>(N64),
        static_cast<int>(C64),
        static_cast<int>(D64),
        static_cast<int>(H64),
        static_cast<int>(W64),
        keepdim ? 1 : 0
    );

    return out;
}
""",
    functions=["lse_channel_reduce"],
    with_cuda=True,
    verbose=False,
    extra_cuda_cflags=["-O3"],
    extra_cflags=["-O3"],
)

class ModelNew(nn.Module):
    """
    Drop-in replacement for Model that accelerates the logsumexp over channels
    using a custom CUDA reduction kernel. Other ops (Conv3d, MaxPool3d, ReLU)
    remain on PyTorch/cuDNN.
    """
    def __init__(self, in_channels: int, out_channels: int, kernel_size: int, stride: int, padding: int):
        super(ModelNew, self).__init__()
        self.conv = nn.Conv3d(in_channels, out_channels, kernel_size, stride=stride, padding=padding)
        self.max_pool = nn.MaxPool3d(kernel_size=2, stride=2)

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        # Reference path for unsupported dtypes/devices
        def ref_logsumexp(t: torch.Tensor) -> torch.Tensor:
            return torch.logsumexp(t, dim=1, keepdim=True)

        x = self.conv(x)
        x = self.max_pool(x)

        # Heuristic gating: only accelerate on CUDA float32 and reasonably sized problems
        use_cuda_path = (
            x.is_cuda and
            x.dtype == torch.float32 and
            x.dim() == 5
        )
        if use_cuda_path:
            # Avoid overhead on tiny workloads
            N, C, D, H, W = x.shape
            spatial_elems = N * D * H * W
            if C >= 8 and spatial_elems >= 2048:
                # Custom CUDA logsumexp over channel dimension (keepdim=True)
                x = kb_ext.lse_channel_reduce(x, True)
            else:
                x = ref_logsumexp(x)
        else:
            x = ref_logsumexp(x)

        x = torch.relu(x)
        return x

