import math
import torch
import torch.nn as nn
import torch.nn.functional as F
from torch.utils.cpp_extension import load_inline
from types import SimpleNamespace

# Build CUDA extension once at import
_cpp_decls = r"""
#include <torch/extension.h>
torch::Tensor fused_add_relu(torch::Tensor a, torch::Tensor b);
"""

_cuda_impl = r"""
#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>
#include <c10/cuda/CUDAGuard.h>
#include <c10/cuda/CUDAException.h>
#include <cuda_runtime.h>
#include <cstdint>

__global__ void fused_add_relu_kernel(
    const float* __restrict__ a,
    const float* __restrict__ b,
    float* __restrict__ out,
    int64_t n
) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    int stride = blockDim.x * gridDim.x;
    for (int64_t i = idx; i < n; i += stride) {
        float v = a[i] + b[i];
        out[i] = v > 0.f ? v : 0.f;
    }
}

__global__ void fused_add_relu_vec4_kernel(
    const float4* __restrict__ a,
    const float4* __restrict__ b,
    float4* __restrict__ out,
    int64_t n4
) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    int stride = blockDim.x * gridDim.x;
    for (int64_t i = idx; i < n4; i += stride) {
        float4 va = a[i];
        float4 vb = b[i];
        float4 r;
        r.x = va.x + vb.x;
        r.y = va.y + vb.y;
        r.z = va.z + vb.z;
        r.w = va.w + vb.w;
        r.x = r.x > 0.f ? r.x : 0.f;
        r.y = r.y > 0.f ? r.y : 0.f;
        r.z = r.z > 0.f ? r.z : 0.f;
        r.w = r.w > 0.f ? r.w : 0.f;
        out[i] = r;
    }
}

static inline int compute_blocks(int64_t work_items, int threads) {
    // Heuristic: cap grid to a multiple of SMs, and avoid excessive oversubscription
    const int sm_count = at::cuda::getCurrentDeviceProperties()->multiProcessorCount;
    int64_t blocks = (work_items + threads - 1) / threads;
    int64_t cap_by_sms = static_cast<int64_t>(sm_count) * 32; // 32x SMs is usually enough to fill the GPU
    if (blocks > cap_by_sms) blocks = cap_by_sms;
    // Conservative cap for grid.x to stay well within limits
    const int64_t max_grid_x = 2147483647; // INT32_MAX
    if (blocks > max_grid_x) blocks = max_grid_x;
    return static_cast<int>(blocks);
}

torch::Tensor fused_add_relu(torch::Tensor a, torch::Tensor b) {
