def _build_fused_bias_tanh_extension():
    cpp_src = r"""
    #include <torch/extension.h>
    // Exposed function declaration
    torch::Tensor bias_tanh_forward(torch::Tensor input_2d, torch::Tensor bias_1d);
    """

    cuda_src = r"""
    #include <torch/extension.h>
    #include <ATen/cuda/CUDAContext.h>
    #include <cuda_runtime.h>
    #include <cstdint>
    #include <cmath>

    template<int VEC>
    __global__ void bias_tanh_kernel(const float* __restrict__ x,
                                     const float* __restrict__ bias,
                                     float* __restrict__ y,
                                     int64_t M) {
      int row = blockIdx.x; // one block per row
      const float* row_x = x + row * M;
      float* row_y = y + row * M;

      int64_t idx = threadIdx.x * VEC;
      int64_t stride = blockDim.x * VEC;

      if constexpr (VEC == 4) {
        for (int64_t j = idx; j + 3 < M; j += stride) {
          float4 vx = reinterpret_cast<const float4*>(row_x)[j/4];
          float4 vb = reinterpret_cast<const float4*>(bias)[j/4];
          vx.x = tanhf(vx.x + vb.x);
          vx.y = tanhf(vx.y + vb.y);
          vx.z = tanhf(vx.z + vb.z);
          vx.w = tanhf(vx.w + vb.w);
          reinterpret_cast<float4*>(row_y)[j/4] = vx;
        }
      } else if constexpr (VEC == 2) {
        for (int64_t j = idx; j + 1 < M; j += stride) {
          float2 vx = reinterpret_cast<const float2*>(row_x)[j/2];
          float2 vb = reinterpret_cast<const float2*>(bias)[j/2];
          vx.x = tanhf(vx.x + vb.x);
          vx.y = tanhf(vx.y + vb.y);
          reinterpret_cast<float2*>(row_y)[j/2] = vx;
        }
      } else {
        for (int64_t j = threadIdx.x; j < M; j += blockDim.x) {
          float v = row_x[j] + bias[j];
          row_y[j] = tanhf(v);
        }
      }

      // Scalar tail for remainders when M not divisible by VEC
      for (int64_t j = ((M / VEC) * VEC) + threadIdx.x; j < M; j += blockDim.x) {
        float v = row_x[j] + bias[j];
        row_y[j] = tanhf(v);
      }
    }

    torch::Tensor bias_tanh_forward(torch::Tensor input_2d, torch::Tensor bias_1d) {
      TORCH_CHECK(input_2d.is_cuda(), "input must be CUDA");
      TORCH_CHECK(bias_1d.is_cuda(), "bias must be CUDA");
      TORCH_CHECK(input_2d.scalar_type() == at::kFloat, "only float32 supported for input");
      TORCH_CHECK(bias_1d.scalar_type() == at::kFloat, "only float32 supported for bias");
      TORCH_CHECK(input_2d.dim() == 2, "input_2d must be 2D [B, M]");
      TORCH_CHECK(bias_1d.dim() == 1, "bias_1d must be 1D [M]");
      TORCH_CHECK(input_2d.size(1) == bias_1d.size(0), "bias length must match input's last dim");

      auto B = input_2d.size(0);
      auto M = input_2d.size(1);

      auto x = input_2d.is_contiguous() ? input_2d : input_2d.contiguous();
      auto b = bias_1d.is_contiguous() ? bias_1d : bias_1d.contiguous();
      auto y = at::empty_like(x);

      const float* x_ptr = x.data_ptr<float>();
      const float* b_ptr = b.data_ptr<float>();
      float* y_ptr = y.data_ptr<float>();

      int threads = (M >= 2048) ? 512 : 256;
      dim3 block(threads);
      dim3 grid(B);
      cudaStream_t stream = at::cuda::getCurrentCUDAStream();

      // Choose vector width based on alignment and size
      bool aligned4 = (M % 4 == 0) &&
                      (((uintptr_t)x_ptr % 16) == 0) &&
                      (((uintptr_t)y_ptr % 16) == 0) &&
                      (((uintptr_t)b_ptr % 16) == 0);
      bool aligned2 = (!aligned4) && (M % 2 == 0) &&
                      (((uintptr_t)x_ptr % 8) == 0) &&
                      (((uintptr_t)y_ptr % 8) == 0) &&
                      (((uintptr_t)b_ptr % 8) == 0);

      if (aligned4) {
        bias_tanh_kernel<4><<<grid, block, 0, stream>>>(x_ptr, b_ptr, y_ptr, M);
      } else if (aligned2) {
        bias_tanh_kernel<2><<<grid, block, 0, stream>>>(x_ptr, b_ptr, y_ptr, M);
      } else {
        bias_tanh_kernel<1><<<grid, block, 0, stream>>>(x_ptr, b_ptr, y_ptr, M);
      }
      C10_CUDA_KERNEL_LAUNCH_CHECK();
      return y;
    }
    """

    try:
        ext = load_inline(
            name=f"fused_bias_tanh_{uuid.uuid4().hex[:8]}",
            cpp_sources=[cpp_src],
            cuda_sources=[cuda_src],
