class BiasTanhFunction(torch.autograd.Function):
    @staticmethod
    def forward(ctx, input_2d: torch.Tensor, bias_1d: torch.Tensor, ext):
        # input_2d: [B, M], bias_1d: [M]
        y = ext.bias_tanh_forward(input_2d, bias_1d)
        ctx.save_for_backward(y)
        return y

    @staticmethod
    def backward(ctx, grad_output: torch.Tensor):
        # y = tanh(z), dy/dz = 1 - y^2
        (y,) = ctx.saved_tensors
        grad_z = grad_output * (1.0 - y * y)
        grad_bias = grad_z.sum(dim=0)
        return grad_z, grad_bias, None


