torch::Tensor linear_matmul_bias_relu(torch::Tensor x,
                                      torch::Tensor w,
                                      torch::Tensor bias,
                                      bool apply_relu) {
    TORCH_CHECK(x.is_cuda(), "x must be a CUDA tensor");
    TORCH_CHECK(w.is_cuda(), "w must be a CUDA tensor");
    TORCH_CHECK(bias.is_cuda(), "bias must be a CUDA tensor");
