import math
from typing import List, Optional

import torch
import torch.nn as nn
import torch.nn.functional as F
from torch.utils.cpp_extension import load_inline

# Build and cache the CUDA extension at import time
kb_ext = load_inline(
    name="kb_ext",
    cpp_sources=[
        r"""
#include <torch/extension.h>

// Declarations only; implementations are in the CUDA source.
torch::Tensor relu6_forward(torch::Tensor input);
torch::Tensor global_avg_pool2d_forward(torch::Tensor input);
"""
    ],
    cuda_sources=[
        r"""
#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>
#include <cuda_runtime.h>

__global__ void relu6_kernel(const float* __restrict__ x, float* __restrict__ y, int64_t n) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    int stride = blockDim.x * gridDim.x;
    for (int64_t i = idx; i < n; i += stride) {
        float v = x[i];
        v = v < 0.f ? 0.f : v;
        v = v > 6.f ? 6.f : v;
        y[i] = v;
    }
}

torch::Tensor relu6_forward(torch::Tensor input) {
    TORCH_CHECK(input.is_cuda(), "relu6_forward: input must be a CUDA tensor");
    TORCH_CHECK(input.dtype() == torch::kFloat32, "relu6_forward: only float32 is supported");
    auto x = input.contiguous();
    auto y = torch::empty_like(x);
    int64_t n = x.numel();
    if (n == 0) return y;
    int threads = 256;
    int blocks = (int)((n + threads - 1) / threads);
    if (blocks < 1) blocks = 1;
    cudaStream_t stream = at::cuda::getCurrentCUDAStream();
    relu6_kernel<<<blocks, threads, 0, stream>>>(x.data_ptr<float>(), y.data_ptr<float>(), n);
    return y;
}

__global__ void gap2d_kernel(const float* __restrict__ x,
                             float* __restrict__ y,
                             int N, int C, int H, int W) {
    int tid = threadIdx.x;
    int nc = blockIdx.x;
    int HW = H * W;
    if (nc >= N * C) return;

    const float* base = x + (int64_t)nc * HW;
    float sum = 0.f;
    for (int i = tid; i < HW; i += blockDim.x) {
        sum += base[i];
    }

    extern __shared__ float sdata[];
    sdata[tid] = sum;
    __syncthreads();

    // Reduce in shared memory down to 64 values
    for (int s = blockDim.x / 2; s >= 64; s >>= 1) {
        if (tid < s) {
            sdata[tid] += sdata[tid + s];
        }
        __syncthreads();
    }

    // Final warp-level reduction (cover the remaining 64 -> 32 first, then warp reduce)
    if (tid < 32) {
        float v = sdata[tid];
        if (blockDim.x >= 64) {
            v += sdata[tid + 32];
        }
        v += __shfl_down_sync(0xffffffff, v, 16);
        v += __shfl_down_sync(0xffffffff, v, 8);
        v += __shfl_down_sync(0xffffffff, v, 4);
        v += __shfl_down_sync(0xffffffff, v, 2);
        v += __shfl_down_sync(0xffffffff, v, 1);
        if (tid == 0) {
            y[nc] = v / (float)HW;
        }
    }
}

torch::Tensor global_avg_pool2d_forward(torch::Tensor input) {
    TORCH_CHECK(input.is_cuda(), "global_avg_pool2d_forward: input must be a CUDA tensor");
    TORCH_CHECK(input.dtype() == torch::kFloat32, "global_avg_pool2d_forward: only float32 is supported");
    TORCH_CHECK(input.dim() == 4, "global_avg_pool2d_forward: input must be 4D NCHW");

    auto x = input.contiguous();
    int N = x.size(0);
    int C = x.size(1);
    int H = x.size(2);
    int W = x.size(3);

    auto y = torch::empty({N, C, 1, 1}, x.options());
    int blocks = N * C;
    if (blocks == 0) return y;

    int threads = 256;
    size_t shmem = threads * sizeof(float);
    cudaStream_t stream = at::cuda::getCurrentCUDAStream();

    gap2d_kernel<<<blocks, threads, shmem, stream>>>(
        x.data_ptr<float>(),
        y.data_ptr<float>(),
        N, C, H, W
    );
    return y;
}
"""
    ],
    functions=["relu6_forward", "global_avg_pool2d_forward"],
    with_cuda=True,
    extra_cuda_cflags=["-O3"],
    extra_cflags=["-O3"],
    verbose=False,
)

class ReLU6Fast(nn.Module):
    def __init__(self):
        super().__init__()

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        # Use custom CUDA path for float32 CUDA tensors; simple heuristic to avoid overhead for tiny tensors
        if x.is_cuda and x.dtype == torch.float32 and x.numel() >= 1024:
            return kb_ext.relu6_forward(x)
        # Fallback to PyTorch implementation
        return torch.clamp(x, min=0.0, max=6.0)

class GlobalAvgPool2dFast(nn.Module):
    def __init__(self):
        super().__init__()

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        # Only handle CUDA float32 here; otherwise use reference op
        if x.is_cuda and x.dtype == torch.float32:
            return kb_ext.global_avg_pool2d_forward(x)
        return F.adaptive_avg_pool2d(x, (1, 1))

class ModelNew(nn.Module):
    def __init__(self, num_classes=1000):
        """
        MobileNetV2 architecture implementation in PyTorch with CUDA-accelerated bottlenecks.

        :param num_classes: The number of output classes. Default is 1000.
        """
        super(ModelNew, self).__init__()

        def _make_divisible(v, divisor, min_value=None):
            if min_value is None:
                min_value = divisor
            new_v = max(min_value, int(v + divisor / 2) // divisor * divisor)
            if new_v < 0.9 * v:
                new_v += divisor
            return new_v

        def _inverted_residual_block(inp, oup, stride, expand_ratio):
            hidden_dim = int(inp * expand_ratio)
            use_res_connect = stride == 1 and inp == oup

            layers = []
            if expand_ratio != 1:
