    TORCH_CHECK(a.is_cuda() && b.is_cuda(), "residual_add_forward: inputs must be CUDA tensors");
    TORCH_CHECK(a.is_contiguous() && b.is_contiguous(), "residual_add_forward: inputs must be contiguous");
    TORCH_CHECK(a.dtype() == at::kFloat && b.dtype() == at::kFloat, "residual_add_forward: inputs must be float32");
    TORCH_CHECK(a.sizes() == b.sizes(), "residual_add_forward: input sizes must match");
    TORCH_CHECK(a.device() == b.device(), "residual_add_forward: inputs must be on the same device");
    auto out = at::empty_like(a);
    cudaStream_t stream = at::cuda::getCurrentCUDAStream();
    launch_residual_add_kernel(a.data_ptr<float>(), b.data_ptr<float>(), out.data_ptr<float>(), a.numel(), stream);
    return out;
}
"""

_cuda_src = r"""
#include <torch/extension.h>
#include <cuda_runtime.h>

template <typename T>
__device__ __forceinline__ T clamp_relu6(T v) {
    v = v < (T)0.0f ? (T)0.0f : v;
    v = v > (T)6.0f ? (T)6.0f : v;
    return v;
}

__global__ void relu6_kernel(const float* __restrict__ in, float* __restrict__ out, long long n) {
    long long idx = blockIdx.x * (long long)blockDim.x + threadIdx.x;
    long long stride = (long long)gridDim.x * blockDim.x;
    for (long long i = idx; i < n; i += stride) {
        float v = in[i];
        out[i] = clamp_relu6<float>(v);
    }
}

__global__ void residual_add_kernel(const float* __restrict__ a, const float* __restrict__ b, float* __restrict__ out, long long n) {
    long long idx = blockIdx.x * (long long)blockDim.x + threadIdx.x;
    long long stride = (long long)gridDim.x * blockDim.x;
    for (long long i = idx; i < n; i += stride) {
        out[i] = a[i] + b[i];
    }
}

extern "C" void launch_relu6_kernel(const float* in, float* out, long long numel, cudaStream_t stream) {
    if (numel <= 0) return;
    int threads = 256;
    long long blocks_ll = (numel + threads - 1) / threads;
    int max_blocks = 65535;
    int blocks = (int)((blocks_ll > max_blocks) ? max_blocks : blocks_ll);
    relu6_kernel<<<blocks, threads, 0, stream>>>(in, out, numel);
}

extern "C" void launch_residual_add_kernel(const float* a, const float* b, float* out, long long numel, cudaStream_t stream) {
    if (numel <= 0) return;
    int threads = 256;
    long long blocks_ll = (numel + threads - 1) / threads;
    int max_blocks = 65535;
    int blocks = (int)((blocks_ll > max_blocks) ? max_blocks : blocks_ll);
    residual_add_kernel<<<blocks, threads, 0, stream>>>(a, b, out, numel);
}
"""

_custom_ext = None
try:
    _custom_ext = load_inline(
        name="custom_kernels_ext_mbconv",
        cpp_sources=[_cpp_src],
        cuda_sources=[_cuda_src],
        functions=["relu6_forward", "residual_add_forward"],
        with_cuda=True,
        extra_cflags=["-O3"],
        extra_cuda_cflags=[
            "-O3",
            "--use_fast_math",
            "-gencode=arch=compute_70,code=compute_70",
            "-gencode=arch=compute_70,code=sm_70"
        ],
        verbose=False,
    )
except Exception:
    _custom_ext = None  # Fallback to PyTorch ops if compilation is not available


def _can_use_ext(t: torch.Tensor, require_large: bool = True) -> bool:
    if _custom_ext is None:
        return False
    if not (t.is_cuda and t.is_contiguous()):
        return False
    if t.dtype != torch.float32:
        return False
    if t.requires_grad:
        return False
    if require_large and t.numel() < 8192:
        return False
    return True


def _relu6_cuda(x: torch.Tensor) -> torch.Tensor:
    # Use custom kernel only for float32, contiguous, no grad, sizeable tensors
    if _can_use_ext(x, require_large=True):
        return _custom_ext.relu6_forward(x)
    # Fallback to PyTorch op with identical semantics
    return torch.clamp(x, 0.0, 6.0)


def _residual_add_cuda(a: torch.Tensor, b: torch.Tensor) -> torch.Tensor:
    # Use custom kernel only if both tensors are eligible
    if _custom_ext is not None and a.is_cuda and b.is_cuda and a.is_contiguous() and b.is_contiguous() and \
       a.dtype == torch.float32 and b.dtype == torch.float32 and (not a.requires_grad) and (not b.requires_grad) and \
       a.numel() >= 8192:
        return _custom_ext.residual_add_forward(a, b)
    # Fallback: PyTorch add
    return a + b


class ModelNew(nn.Module):
    def __init__(self, in_channels, out_channels, kernel_size, stride, expand_ratio):
        """
        MBConv block implementation (drop-in replacement).
        """
        super(ModelNew, self).__init__()

        self.use_residual = (stride == 1 and in_channels == out_channels)
        hidden_dim = in_channels * expand_ratio
        self.hidden_dim = hidden_dim
        self.expand_ratio = expand_ratio

        if expand_ratio != 1:
            self.expand_conv = nn.Conv2d(in_channels, hidden_dim, kernel_size=1, stride=1, padding=0, bias=False)
            self.expand_bn = nn.BatchNorm2d(hidden_dim)

        padding = (kernel_size - 1) // 2
        self.depthwise_conv = nn.Conv2d(hidden_dim, hidden_dim, kernel_size=kernel_size, stride=stride,
                                        padding=padding, groups=hidden_dim, bias=False)
        self.depthwise_bn = nn.BatchNorm2d(hidden_dim)

        self.project_conv = nn.Conv2d(hidden_dim, out_channels, kernel_size=1, stride=1, padding=0, bias=False)
        self.project_bn = nn.BatchNorm2d(out_channels)

    def forward(self, x):
        """
        Forward pass of the MBConv block.

        :param x: The input tensor, shape (N, C_in, H, W)
        :return: The output tensor, shape (N, C_out, H', W')
        """
        identity = x

        # Expand (if any): Conv -> BN -> ReLU6
        if hasattr(self, 'expand_conv'):
            x = self.expand_conv(x)
            x = self.expand_bn(x)
            if (not self.training) and _can_use_ext(x, require_large=True):
                x = _relu6_cuda(x)
            else:
                x = F.relu6(x, inplace=False)

        # Depthwise: Conv -> BN -> ReLU6
        x = self.depthwise_conv(x)
        x = self.depthwise_bn(x)
        if (not self.training) and _can_use_ext(x, require_large=True):
            x = _relu6_cuda(x)
        else:
            x = F.relu6(x, inplace=False)

        # Project: Conv -> BN
        x = self.project_conv(x)
        x = self.project_bn(x)

        # Residual add if applicable
        if self.use_residual:
            if (not self.training) and _custom_ext is not None and identity.is_cuda and x.is_cuda:
                x = _residual_add_cuda(x, identity)
            else:
                x = x + identity

        return x

