#include <torch/extension.h>
#include <cuda_runtime.h>
#include <ATen/cuda/CUDAContext.h>

template <typename T>
__global__ void bias_relu6_kernel(const T* __restrict__ x,
                                  const T* __restrict__ bias,
                                  T* __restrict__ y,
                                  int64_t N, int64_t C, int64_t HW) {
  int64_t idx = blockIdx.x * blockDim.x + threadIdx.x;
  int64_t total = N * C * HW;
  for (; idx < total; idx += blockDim.x * gridDim.x) {
    int64_t hw = idx % HW;
    int64_t tmp = idx / HW;
    int64_t c = tmp % C;
    int64_t n = tmp / C;
    (void)hw; (void)n;
    float v = static_cast<float>(x[idx]) + static_cast<float>(bias[c]);
    v = fminf(fmaxf(v, 0.0f), 6.0f);
    y[idx] = static_cast<T>(v);
  }
}

torch::Tensor bias_relu6_forward(torch::Tensor x, torch::Tensor bias) {
  TORCH_CHECK(x.is_cuda(), "x must be CUDA");
  TORCH_CHECK(bias.is_cuda(), "bias must be CUDA");
  TORCH_CHECK(x.is_contiguous(), "x must be contiguous");
  TORCH_CHECK(bias.is_contiguous(), "bias must be contiguous");
  TORCH_CHECK(x.dim() == 4, "x must be NCHW");
  TORCH_CHECK(bias.dim() == 1, "bias must be 1D");
  int64_t N = x.size(0), C = x.size(1), H = x.size(2), W = x.size(3);
  TORCH_CHECK(bias.size(0) == C, "bias size must match C");
  auto y = torch::empty_like(x);
  int64_t HW = H * W;
  int threads = 256;
  int64_t total = N * C * HW;
  int blocks = (int)((total + threads - 1) / threads);
  blocks = max(1, min(blocks, 65535));
  cudaStream_t stream = at::cuda::getCurrentCUDAStream();
  if (x.scalar_type() == at::kFloat) {
    bias_relu6_kernel<float><<<blocks, threads, 0, stream>>>(
      x.data_ptr<float>(), bias.data_ptr<float>(), y.data_ptr<float>(), N, C, HW);
  } else if (x.scalar_type() == at::kHalf) {
    bias_relu6_kernel<at::Half><<<blocks, threads, 0, stream>>>(
      x.data_ptr<at::Half>(), bias.data_ptr<at::Half>(), y.data_ptr<at::Half>(), N, C, HW);
  } else {
    TORCH_CHECK(false, "Unsupported dtype");
  }
  return y;
}

