#include <torch/extension.h>
#include <cuda_runtime.h>
#include <ATen/cuda/CUDAContext.h>

// Normalize: y = (x - mean[c]) / sqrt(var[c] + eps) * weight[c] + bias[c]
template <typename T>
__global__ void bn2d_infer_kernel(const T* __restrict__ x, const T* __restrict__ w,
                                  const T* __restrict__ b, const T* __restrict__ m,
                                  const T* __restrict__ v, T* __restrict__ y,
                                  int64_t N, int64_t C, int64_t H, int64_t W, float eps) {
  int64_t idx = blockIdx.x * blockDim.x + threadIdx.x;
  int64_t total = N * C * H * W;
  for (; idx < total; idx += blockDim.x * gridDim.x) {
    int64_t hw = idx % (H * W);
    int64_t tmp = idx / (H * W);
    int64_t c = tmp % C;
    (void)hw;
    float xv = static_cast<float>(x[idx]);
    float invstd = rsqrtf(static_cast<float>(v[c]) + eps);
    float yv = (xv - static_cast<float>(m[c])) * invstd;
    y[idx] = static_cast<T>(yv * static_cast<float>(w[c]) + static_cast<float>(b[c]));
  }
}

torch::Tensor bn2d_inference_forward(torch::Tensor x, torch::Tensor weight, torch::Tensor bias, torch::Tensor mean, torch::Tensor var, double eps) {
  TORCH_CHECK(x.is_cuda() && weight.is_cuda() && bias.is_cuda() && mean.is_cuda() && var.is_cuda(), "All tensors must be CUDA");
  TORCH_CHECK(x.is_contiguous(), "x must be contiguous");
  TORCH_CHECK(x.dim() == 4, "x must be NCHW");
  int64_t N = x.size(0), C = x.size(1), H = x.size(2), W = x.size(3);
  TORCH_CHECK(weight.numel() == C && bias.numel() == C && mean.numel() == C && var.numel() == C, "BN params must be size C");
  auto y = torch::empty_like(x);
  int64_t total = N * C * H * W;
  int threads = 256;
  int blocks = (int)((total + threads - 1) / threads);
  blocks = max(1, min(blocks, 65535));
  cudaStream_t stream = at::cuda::getCurrentCUDAStream();
  if (x.scalar_type() == at::kFloat) {
    bn2d_infer_kernel<float><<<blocks, threads, 0, stream>>>(
      x.data_ptr<float>(), weight.data_ptr<float>(), bias.data_ptr<float>(), mean.data_ptr<float>(), var.data_ptr<float>(), y.data_ptr<float>(), N, C, H, W, (float)eps);
  } else if (x.scalar_type() == at::kHalf) {
    bn2d_infer_kernel<at::Half><<<blocks, threads, 0, stream>>>(
      x.data_ptr<at::Half>(), weight.data_ptr<at::Half>(), bias.data_ptr<at::Half>(), mean.data_ptr<at::Half>(), var.data_ptr<at::Half>(), y.data_ptr<at::Half>(), N, C, H, W, (float)eps);
  } else {
    TORCH_CHECK(false, "Unsupported dtype");
  }
  return y;
}

